'use client';

import React, { useEffect, useState, useMemo } from 'react';
import { coreDb } from '@/lib/db/SystemDB';
import { useLanguage } from '@/lib/context/LanguageContext';
import { ShieldCheckIcon, SearchIcon, RefreshCwIcon, ArrowRightIcon } from '@/components/common/Icons';
import { AuditDetails } from '@/lib/types/auth.types';
import Link from 'next/link';

type FilterMode = 'ALL' | 'SECURITY' | 'SYSTEM';
type SeverityFilter = 'ALL' | 'INFO' | 'WARN' | 'CRITICAL';
type EventCategory = 'AUTH' | 'WORKSPACE' | 'OPERATORS' | 'CONFIG' | 'OTHER';

interface AuditRow {
  id: string;
  timestamp: number;
  module: string;
  action: string;
  status: string;
  details: AuditDetails | null;
}

const getCategory = (log: AuditRow): EventCategory => {
  const type = log.details?.eventType || '';
  if (type.startsWith('AUTH')) return 'AUTH';
  if (type.startsWith('WORKSPACE')) return 'WORKSPACE';
  if (type.startsWith('OPERATOR')) return 'OPERATORS';
  if (type.endsWith('CONFIG_UPDATE')) return 'CONFIG';
  return 'OTHER';
};

interface SecurityAuditPanelProps {
  initialEventType?: string;
}

export const SecurityAuditPanel: React.FC<SecurityAuditPanelProps> = ({ initialEventType }) => {
  const { t } = useLanguage();
  const [logs, setLogs] = useState<AuditRow[]>([]);
  const [mode, setMode] = useState<FilterMode>('SECURITY');
  const [typeFilter, setTypeFilter] = useState<string>(initialEventType ?? 'ALL');
  const [severityFilter, setSeverityFilter] = useState<SeverityFilter>('ALL');
  const [categoryFilter, setCategoryFilter] = useState<'ALL' | EventCategory>('ALL');
  const [isLoading, setIsLoading] = useState(true);

  // Sync with external filters (Phase 13 Drill-down)
  useEffect(() => {
    if (initialEventType) {
      setTypeFilter(initialEventType);
      setMode('SECURITY');
    }
  }, [initialEventType]);

  const loadLogs = async () => {
    setIsLoading(true);
    try {
      const all = await coreDb.system_log
        .orderBy('timestamp')
        .reverse()
        .limit(500)
        .toArray();

      const mapped: AuditRow[] = all.map(log => {
        let details: AuditDetails | null = null;
        try {
          details = JSON.parse(log.details || '{}');
        } catch {
          details = null;
        }
        return {
          id: log.id,
          timestamp: log.timestamp,
          module: 'SECURITY', // Heuristic for system_log events
          action: log.action,
          status: log.status,
          details
        };
      });

      setLogs(mapped);
    } catch (err) {
      console.error('[SECURITY-AUDIT] Load failed', err);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    loadLogs();
  }, []);

  const eventTypes = useMemo(() => {
    const types = new Set<string>();
    logs.forEach(l => {
      if (l.details?.eventType) types.add(l.details.eventType);
    });
    return Array.from(types).sort();
  }, [logs]);

  const filteredLogs = useMemo(() => {
    return logs.filter(log => {
      if (mode === 'SECURITY' && log.module !== 'SECURITY') return false;
      if (typeFilter !== 'ALL' && log.details?.eventType !== typeFilter) return false;
      if (severityFilter !== 'ALL' && log.details?.severity !== severityFilter) return false;
      if (categoryFilter !== 'ALL' && getCategory(log) !== categoryFilter) return false;
      return true;
    });
  }, [logs, mode, typeFilter, severityFilter, categoryFilter]);

  const resolveMessage = (entry: AuditRow) => {
    const i18nKey = `audit.${entry.action}`;
    const translated = t(i18nKey);

    if (translated === i18nKey) return entry.action;

    let msg = translated;
    const context = entry.details?.context || {};
    Object.entries(context).forEach(([key, val]) => {
      msg = msg.replace(`{${key}}`, String(val));
    });

    // Also support actorUser in interpolation if provided at top level
    if (entry.details?.actorUser) {
      msg = msg.replace('{actorUser}', entry.details.actorUser);
    }

    return msg;
  };

  return (
    <section className="flex-col animate-fade-in" style={{ gap: '16px', height: '100%' }}>
      <header className="flex-col" style={{ gap: '16px' }}>
        <div className="flex-row" style={{ justifyContent: 'space-between', alignItems: 'center' }}>
          <div className="flex-row" style={{ gap: '12px', alignItems: 'center' }}>
            <ShieldCheckIcon size={20} color="var(--primary-color)" />
            <h3 style={{ margin: 0, fontSize: '0.75rem', letterSpacing: '2px', opacity: 0.5 }}>{t('audit.securityTitle').toUpperCase()}</h3>
          </div>
          <button className="station-btn secondary tiny" onClick={loadLogs} disabled={isLoading}>
            <RefreshCwIcon size={14} className={isLoading ? 'spin' : ''} />
          </button>
        </div>

        <div className="flex-row" style={{ gap: '16px', flexWrap: 'wrap' }}>
          <div className="flex-col">
            <label className="station-label" style={{ fontSize: '0.65rem' }}>MODULE</label>
            <select className="station-input" value={mode} onChange={e => setMode(e.target.value as any)} style={{ height: '32px', fontSize: '0.75rem' }}>
              <option value="SECURITY">SECURITY_ONLY</option>
              <option value="ALL">ALL_GLOBAL_SYSTEM</option>
            </select>
          </div>

          <div className="flex-col">
            <label className="station-label" style={{ fontSize: '0.65rem' }}>CATEGORY</label>
            <select className="station-input" value={categoryFilter} onChange={e => setCategoryFilter(e.target.value as any)} style={{ height: '32px', fontSize: '0.75rem' }}>
              <option value="ALL">ALL_CATEGORIES</option>
              <option value="AUTH">AUTH</option>
              <option value="WORKSPACE">WORKSPACE</option>
              <option value="OPERATORS">OPERATORS</option>
              <option value="CONFIG">CONFIG</option>
              <option value="OTHER">OTHER</option>
            </select>
          </div>

          <div className="flex-col">
            <label className="station-label" style={{ fontSize: '0.65rem' }}>EVENT_TYPE</label>
            <select className="station-input" value={typeFilter} onChange={e => setTypeFilter(e.target.value)} style={{ height: '32px', fontSize: '0.75rem' }}>
              <option value="ALL">ALL_TYPES</option>
              {eventTypes.map(type => (
                <option key={type} value={type}>{type}</option>
              ))}
            </select>
          </div>

          <div className="flex-col">
            <label className="station-label" style={{ fontSize: '0.65rem' }}>SEVERITY</label>
            <select className="station-input" value={severityFilter} onChange={e => setSeverityFilter(e.target.value as any)} style={{ height: '32px', fontSize: '0.75rem' }}>
              <option value="ALL">ALL_SEVERITIES</option>
              <option value="INFO">INFO</option>
              <option value="WARN">WARNING</option>
              <option value="CRITICAL">CRITICAL</option>
            </select>
          </div>
        </div>
      </header>

      <div className="station-table-wrapper" style={{ flex: 1, overflow: 'auto' }}>
        <table className="station-table">
          <thead>
            <tr>
              <th style={{ width: '160px' }}>{t('audit.colTime').toUpperCase()}</th>
              <th style={{ width: '140px' }}>CATEGORY / TYPE</th>
              <th style={{ width: '120px' }}>ACTOR</th>
              <th style={{ width: '120px' }}>ENTITY</th>
              <th>{t('audit.colMessage').toUpperCase()}</th>
              <th style={{ width: '80px' }}>SEV</th>
            </tr>
          </thead>
          <tbody>
            {filteredLogs.map(log => (
              <tr key={log.id}>
                <td style={{ opacity: 0.6, fontSize: '0.75rem' }}>
                  {new Date(log.timestamp).toLocaleString()}
                </td>
                <td style={{ fontSize: '0.65rem', fontWeight: 600 }}>
                  <div style={{ opacity: 0.5 }}>{getCategory(log)}</div>
                  <div style={{ color: 'var(--accent-primary)' }}>{log.details?.eventType || log.action}</div>
                </td>
                <td>
                  {log.details?.actorId ? (
                    <Link 
                      href={`/supervisor?tab=operators&operatorId=${encodeURIComponent(log.details.actorId)}`}
                      className="audit-link"
                    >
                      {log.details.actorUser || log.details.actorId.split('-')[0]}
                    </Link>
                  ) : '—'}
                </td>
                <td>
                  {log.details?.entityType === 'OPERATOR' && log.details.entityId ? (
                    <Link 
                      href={`/supervisor?tab=operators&operatorId=${encodeURIComponent(log.details.entityId)}`}
                      className="audit-link"
                    >
                      OP:{log.details.entityId.split('-')[0]}
                    </Link>
                  ) : (
                    <span style={{ fontSize: '0.7rem', opacity: 0.7 }}>
                      {log.details?.entityType || '—'}{log.details?.entityId ? `:${log.details.entityId.split('-')[0]}` : ''}
                    </span>
                  )}
                </td>
                <td>
                  <div style={{ wordBreak: 'break-word', maxWidth: '500px', fontSize: '0.85rem' }}>
                    {resolveMessage(log)}
                  </div>
                </td>
                <td>
                  <span className={`status-badge ${(log.details?.severity || 'INFO').toLowerCase()}`}>
                    {log.details?.severity || 'INFO'}
                  </span>
                </td>
              </tr>
            ))}
            {filteredLogs.length === 0 && (
              <tr>
                <td colSpan={6} style={{ textAlign: 'center', opacity: 0.5, padding: '40px' }}>
                  {t('audit.emptySecurity')}
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      <style jsx>{`
        .status-badge {
          font-size: 0.55rem;
          padding: 2px 6px;
          border-radius: 2px;
          background: var(--bg-color);
          border: 1px solid var(--border-color);
          letter-spacing: 1px;
          font-weight: 900;
          font-family: var(--font-mono);
        }
        .status-badge.critical { color: var(--status-err); border-color: var(--status-err); background: rgba(239, 68, 68, 0.05); }
        .status-badge.warn { color: var(--status-warn); border-color: var(--status-warn); }
        .status-badge.info { color: var(--primary-color); border-color: var(--primary-color); }

        .audit-link {
          color: var(--primary-color);
          text-decoration: none;
          font-family: var(--font-mono);
          font-size: 0.75rem;
          font-weight: 600;
          display: inline-flex;
          align-items: center;
          gap: 4px;
        }
        .audit-link:hover {
          text-decoration: underline;
        }
      `}</style>
    </section>
  );
};

'use client';

import React, { useState, useEffect, useMemo } from 'react';
import { db } from '@/lib/db/db';
import { useLanguage } from '@/lib/context/LanguageContext';
import { useWorkspace } from '@/lib/context/WorkspaceContext';
import { ForbiddenPanel } from '../common/ForbiddenPanel';
import { IndustrialVirtualTable } from '../common/IndustrialVirtualTable';
import { 
  ListIcon, 
  SearchIcon, 
  AlertTriangleIcon, 
  ActivityIcon, 
  ShieldIcon, 
  ClockIcon,
  CheckCircleIcon,
  InfoIcon
} from '../common/Icons';
import { loadAuditRetention, saveAuditRetention, AuditRetentionSettings } from '@/lib/utils/audit-retention-settings';
import { purgeOldAuditRecords } from '@/lib/utils/audit-retention';

import { useSecurityKpis, SecurityKpis } from '@/lib/hooks/useSecurityKpis';
import { AuditCategory } from '@/lib/types/audit.types';
import { auditService } from '@/lib/services/AuditService';
import { TelemetryConfigService } from '@/lib/services/telemetry-config.service';

const ITEM_HEIGHT = 48;

/**
 * Enterprise Security Audit Dashboard (Phase 14.3 Refined)
 */
export const AuditHistoryDashboard: React.FC = () => {
    const { t } = useLanguage();
    const { can, currentOperator } = useWorkspace();

    if (!can('AUDIT_VIEW')) {
        return <ForbiddenPanel capability="AUDIT_VIEW" />;
    }

    const [records, setRecords] = useState<any[]>([]);
    const [categoryFilter, setCategoryFilter] = useState<AuditCategory | 'ALL'>('ALL');
    const [severityFilter, setSeverityFilter] = useState<string | 'ALL'>('ALL');
    const [selectedId, setSelectedId] = useState<string | null>(null);
    const [retention, setRetention] = useState<AuditRetentionSettings>(() => loadAuditRetention());

    // Time Range State
    const [timeRange, setTimeRange] = useState<number>(24); // hours
    const toTs = Date.now();
    const fromTs = toTs - (timeRange * 60 * 60 * 1000);

    const { kpis, isLoading: kpisLoading } = useSecurityKpis(fromTs, toTs);

    const handleRetentionChange = async (months: number) => {
        const next = { months: months as any };
        setRetention(next);
        saveAuditRetention(next);
        purgeOldAuditRecords();

        await auditService.log({
          module: 'AUDIT',
          messageKey: 'audit.config.update',
          status: 'WARNING',
          operatorId: currentOperator?.id,
          details: {
            eventType: 'AUDIT_CONFIG_UPDATE',
            entityType: 'AUDIT_CONFIG',
            entityId: 'GLOBAL',
            actorId: currentOperator?.id,
            actorUser: currentOperator?.username,
            severity: 'WARN',
            context: {
              retentionMonths: months
            }
          }
        });
    };

    const [telemetry, setTelemetry] = useState<any>(null);

    useEffect(() => {
        TelemetryConfigService.loadConfig().then(setTelemetry);
    }, []);

    /**
     * Security Health Summary Logic (Phase 15 Parametrized)
     */
    const healthSummary = useMemo(() => {
        if (!telemetry) return [];
        const sentences: { text: string; status: 'ok' | 'warn' | 'crit'; type: AuditCategory | 'ALL' }[] = [];
        const thresholds = telemetry.security.securityThresholds;

        // 1. Auth Failures
        if (kpis.failedAuthCount === 0) {
            sentences.push({ text: 'No se han detectado intentos de acceso fallidos en la ventana seleccionada.', status: 'ok', type: 'AUTH' });
        } else if (kpis.failedAuthCount < thresholds.failedAuthLow) {
            sentences.push({ text: `Se han registrado ${kpis.failedAuthCount} intentos de acceso fallidos; el nivel de ruido de autenticación es bajo.`, status: 'ok', type: 'AUTH' });
        } else if (kpis.failedAuthCount < thresholds.failedAuthHigh) {
            sentences.push({ text: `Atención: se han registrado ${kpis.failedAuthCount} intentos de acceso fallidos. Revisar patrones de acceso.`, status: 'warn', type: 'AUTH' });
        } else {
            sentences.push({ text: `ALERTA: volumen crítico (${kpis.failedAuthCount}) de intentos fallidos; posible ataque o desajuste grave de terminales.`, status: 'crit', type: 'AUTH' });
        }

        // 2. Session Locks
        const totalLocks = kpis.sessionLocks.inactivity + kpis.sessionLocks.manual;
        if (totalLocks === 0) {
            sentences.push({ text: 'No se han producido bloqueos de estación; verifique que los timeouts de sesión son adecuados.', status: 'warn', type: 'AUTH' });
        } else if (kpis.sessionLocks.inactivity > thresholds.inactivityLocksHigh) {
            sentences.push({ text: `Volumen elevado de bloqueos por inactividad (${kpis.sessionLocks.inactivity}); revise la ergonomía de seguridad en la planta.`, status: 'warn', type: 'AUTH' });
        } else {
            sentences.push({ text: `Se han producido ${kpis.sessionLocks.inactivity} bloqueos por inactividad y ${kpis.sessionLocks.manual} bloqueos manuales.`, status: 'ok', type: 'AUTH' });
        }

        // 3. RBAC Changes
        if (kpis.rbacChangesCount === 0) {
            sentences.push({ text: 'No se han realizado cambios de roles ni capacidades en este periodo.', status: 'ok', type: 'RBAC' });
        } else if (kpis.rbacChangesCount >= thresholds.rbacChangesAttention) {
            sentences.push({ text: `Se han registrado ${kpis.rbacChangesCount} cambios en Operadores/Roles; nivel superior al umbral configurado.`, status: 'warn', type: 'RBAC' });
        } else {
            sentences.push({ text: `${kpis.rbacChangesCount} cambios menores de administración detectados.`, status: 'ok', type: 'RBAC' });
        }

        // 4. Data Operations
        if (kpis.dataOps.total === 0) {
            sentences.push({ text: 'No se han realizado volcados ni sincronizaciones de datos.', status: 'ok', type: 'DATA' });
        } else {
            const hasTooManyErrors = kpis.dataOps.failed >= thresholds.dataOpsErrorAttention;
            sentences.push({ 
                text: `Operaciones de datos: ${kpis.dataOps.total} (éxito: ${kpis.dataOps.success}, fallos: ${kpis.dataOps.failed}).`, 
                status: hasTooManyErrors ? 'crit' : 'ok', 
                type: 'DATA' 
            });
        }

        return sentences;
    }, [kpis, telemetry]);

    useEffect(() => {
        const fetchHistory = async () => {
            let collection = db.audit_history_v6.where('timestamp').between(fromTs, toTs, true, true);

            // Filtering at source where possible, or in memory for complex and conditions
            let data = await collection.toArray();

            if (categoryFilter !== 'ALL') {
                data = data.filter(r => r.category === categoryFilter);
            }

            if (severityFilter !== 'ALL') {
              data = data.filter(r => {
                try {
                  const details = JSON.parse(r.details || '{}');
                  return details.severity === severityFilter;
                } catch { return false; }
              });
            }

            // Reverse and limit
            data.sort((a, b) => b.timestamp - a.timestamp);
            setRecords(data.slice(0, 500));
        };
        fetchHistory();
    }, [categoryFilter, severityFilter, fromTs, toTs]);

    const renderRow = (record: any | undefined, idx: number, style: React.CSSProperties) => {
        if (!record) return <div style={style}>...</div>;
        const isSelected = selectedId === record.id;

        let severity = 'INFO';
        try {
           severity = JSON.parse(record.details).severity || 'INFO';
        } catch {}

        return (
            <div
                key={record.id}
                onClick={() => setSelectedId(record.id)}
                style={{
                    ...style,
                    display: 'flex',
                    alignItems: 'center',
                    padding: '0 16px',
                    borderBottom: '1px solid var(--border-color)',
                    background: isSelected ? 'rgba(var(--primary-color), 0.1)' : 'transparent',
                    cursor: 'pointer',
                    transition: 'background 0.2s ease',
                    fontSize: '0.85rem'
                }}
            >
                <div style={{ width: '140px', opacity: 0.6, fontSize: '0.75rem' }}>
                    {new Date(record.timestamp).toLocaleString()}
                </div>
                <div style={{ width: '100px' }}>
                    <span className={`station-badge station-badge-${record.category === 'AUTH' ? 'orange' : record.category === 'RBAC' ? 'green' : record.category === 'CONFIG' ? 'blue' : 'blue'}`}>
                        {record.category}
                    </span>
                </div>
                <div style={{ flex: 1, fontWeight: 500, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                    {t(record.action) || record.action}
                </div>
                <div style={{ width: '80px', textAlign: 'right' }}>
                    <span className={`station-badge ${severity === 'CRITICAL' ? 'station-badge-orange' : severity === 'WARN' ? 'station-badge-blue' : ''}`} style={{ fontSize: '0.65rem' }}>
                        {severity}
                    </span>
                </div>
            </div>
        );
    };

    const selectedRecord = records.find(r => r.id === selectedId);

    return (
        <div style={{ display: 'flex', flexDirection: 'column', height: '100%', gap: '20px' }}>

            {/* SECURITY HEALTH SUMMARY (Phase 14.3 Template) */}
            <div className="station-card" style={{ background: 'var(--surface-color)', borderLeft: '4px solid var(--primary-color)', padding: '16px 20px' }}>
               <div className="flex-col" style={{ gap: '12px' }}>
                  <div className="flex-row" style={{ alignItems: 'center', gap: '10px' }}>
                     <ShieldIcon size={18} color="var(--primary-color)" />
                     <div style={{ fontWeight: 800, fontSize: '0.85rem', letterSpacing: '0.5px' }}>RESUMEN DE SALUD DE SEGURIDAD (DIAGNÓSTICO AUTOMÁTICO)</div>
                  </div>
                  <div className="flex-col" style={{ gap: '8px' }}>
                    {healthSummary.map((sentence, idx) => (
                      <div 
                        key={idx} 
                        className="health-sentence clickable"
                        onClick={() => setCategoryFilter(sentence.type)}
                        style={{ 
                          display: 'flex', 
                          gap: '10px', 
                          alignItems: 'baseline', 
                          fontSize: '0.8rem',
                          background: 'rgba(0,0,0,0.02)',
                          padding: '6px 12px',
                          borderRadius: '4px',
                          border: '1px solid transparent',
                          transition: 'all 0.2s ease',
                          cursor: 'pointer'
                        }}
                      >
                        {sentence.status === 'ok' ? <CheckCircleIcon size={14} color="var(--status-ok)" /> : 
                         sentence.status === 'warn' ? <InfoIcon size={14} color="var(--status-warn)" /> : 
                         <AlertTriangleIcon size={14} color="var(--error-color)" />}
                        <span style={{ flex: 1 }}>{sentence.text}</span>
                        <span style={{ fontSize: '0.6rem', opacity: 0.4, fontWeight: 700 }}>[FILTRAR]</span>
                      </div>
                    ))}
                  </div>
               </div>
            </div>

            {/* KPI CARDS (v2 Parametrized) */}
            <div className="station-form-grid" style={{ gridTemplateColumns: 'repeat(5, 1fr)' }}>
               <KPIItem 
                 val={kpis.failedAuthCount} 
                 label="AUTH_FAILURES" 
                 status={telemetry ? (kpis.failedAuthCount >= telemetry.security.securityThresholds.failedAuthHigh ? 'crit' : kpis.failedAuthCount >= telemetry.security.securityThresholds.failedAuthLow ? 'warn' : 'ok') : 'ok'} 
               />
               <KPIItem 
                 val={kpis.sessionLocks.inactivity + kpis.sessionLocks.manual} 
                 label={`SESSION_LOCKS (I:${kpis.sessionLocks.inactivity}/M:${kpis.sessionLocks.manual})`}
                 status={telemetry ? (kpis.sessionLocks.inactivity > telemetry.security.securityThresholds.inactivityLocksHigh ? 'warn' : 'ok') : 'ok'} 
               />
               <KPIItem 
                 val={kpis.rbacChangesCount} 
                 label="RBAC_ALTS" 
                 status={telemetry ? (kpis.rbacChangesCount >= telemetry.security.securityThresholds.rbacChangesAttention ? 'warn' : 'ok') : 'ok'} 
               />
               <KPIItem 
                 val={`${kpis.dataOps.success}/${kpis.dataOps.failed}`} 
                 label="DATA_OPS (OK/ERR)" 
                 status={telemetry ? (kpis.dataOps.failed >= telemetry.security.securityThresholds.dataOpsErrorAttention ? 'crit' : 'ok') : 'ok'} 
               />
               <KPIItem 
                 val={kpis.ikUnlocks} 
                 label="IK_UNLOCKS" 
                 status={kpis.ikUnlocks > 1 ? 'warn' : 'ok'} 
               />
            </div>

            {/* TOOLBAR */}
            <div className="flex-row" style={{ gap: '16px', alignItems: 'center', flexWrap: 'wrap' }}>
                <div className="flex-col">
                    <label className="station-label" style={{ fontSize: '0.65rem' }}>CATEGORÍA</label>
