'use client';

import React, { useState } from 'react';
import { useLanguage } from '@/lib/context/LanguageContext';
import { useWorkspace } from '@/lib/context/WorkspaceContext';
import { coreDb } from '@/lib/db/SystemDB';
import { hashPin } from '@/lib/utils/crypto.utils';
import { ShieldAlertIcon, UserPlusIcon, BuildingIcon, CheckIcon, LoaderIcon } from '../common/Icons';
import { UserRole } from '@/lib/types/auth.types';

export const BootstrapWizard: React.FC = () => {
  const { t } = useLanguage();
  const { refreshBootstrapStatus } = useWorkspace();
  const [step, setStep] = useState(1);
  const [isLoading, setIsLoading] = useState(false);

  // Admin Data
  const [adminName, setAdminName] = useState('SISTEMAS');
  const [adminUsername, setAdminUsername] = useState('master');
  const [adminRole, setAdminRole] = useState<UserRole>('ADMIN');
  const [pin, setPin] = useState('');
  const [pinConfirm, setPinConfirm] = useState('');

  // Unit Data
  const [unitCode, setUnitCode] = useState('UNIT01');
  const [unitName, setUnitName] = useState('');

  const [error, setError] = useState<string | null>(null);

  const handleBootstrap = async () => {
    if (pin !== pinConfirm) {
      setError('auth.bootstrap.error_pin_mismatch');
      return;
    }
    if (pin.length < 4 || pin.length > 6 || !/^\d+$/.test(pin)) {
      setError('auth.bootstrap.error_pin_format');
      return;
    }

    setIsLoading(true);
    setError(null);

    try {
      const unitId = crypto.randomUUID();
      const adminId = crypto.randomUUID();
      const pinHash = await hashPin(pin);
      console.log(`[ABDFN-BOOTSTRAP] Admin initialized with PIN Hash: ${pinHash}`);

      // --- PHASE 14: AT-REST SECURITY INITIALIZATION ---
      const { CryptoService } = await import('@/lib/services/crypto.service');

      // 1. Generate Global Installation Key (IK) as bytes
      const ik = await CryptoService.generateInstallationKey();
      const ikBytes = await crypto.subtle.exportKey('raw', ik);

      // 2. Prepare master salt and derive Master Key from the initial PIN
      const masterSalt = crypto.getRandomValues(new Uint8Array(16));
      const masterKey = await CryptoService.deriveMasterKeyFromPin(pin, masterSalt);

      // 3. Wrap IK bytes into an EncryptedFieldContainer
      // For the IK itself, we use a fixed AAD context as it's the root of the core
      const ikAad = CryptoService.buildAAD('ABDFN_CORE', null, 'coreSettings', 'global', 'encryptedInstallationKey');
      const encryptedIK = await CryptoService.encryptField(ikBytes, masterKey, ikAad);

      // 4. Save to Core Settings (use put to overwrite existing if needed)
      await coreDb.coreSettings.put({
        id: 'global',
        encryptedInstallationKey: encryptedIK,
        masterSalt: CryptoService.toBase64(masterSalt),
        createdAt: Date.now()
      });

      // --- END PHASE 14 ---

      // 1. Create Unit
      await coreDb.units.add({
        id: unitId,
        code: unitCode,
        name: unitName || 'PRE-DEPÁRTAMENTO',
        createdAt: Date.now(),
        updatedAt: Date.now(),
        isActive: 1
      });

      // 2. Create Admin
      await coreDb.operators.add({
        id: adminId,
        displayName: adminName || 'SISTEMAS',
        username: adminUsername || 'master',
        pinHash,
        role: adminRole,
        unitIds: [unitId],
        createdAt: Date.now(),
        updatedAt: Date.now(),
        lastLogin: Date.now(),
        isActive: 1,
        isMaster: true,
        mfaEnabled: false
      });

      await refreshBootstrapStatus();
    } catch (err) {
      console.error('[ABDFN-BOOTSTRAP] Critical Failure', err);
      setError('auth.bootstrap.error_save_failed');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="station-modal-overlay" style={{ background: 'var(--bg-primary)' }}>
      <div className="station-modal" style={{ maxWidth: '500px', border: '1px solid var(--accent-primary)' }}>
        <header className="station-modal-header" style={{ borderColor: 'var(--accent-primary)' }}>
          <div className="flex-row" style={{ gap: '12px' }}>
            <ShieldAlertIcon size={24} color="var(--accent-primary)" />
            <div className="flex-col">
              <h2 className="station-modal-title" style={{ fontSize: '1.2rem' }}>{t('bootstrap.title')}</h2>
              <p className="station-modal-subtitle" style={{ color: 'var(--accent-primary)' }}>{t('bootstrap.subtitle')}</p>
            </div>
          </div>
        </header>

        <div className="station-modal-body" style={{ padding: '32px' }}>
          {step === 1 && (
            <div className="flex-col animate-fade-in" style={{ gap: '24px' }}>
              <div className="flex-row" style={{ gap: '8px', opacity: 0.7 }}>
                <UserPlusIcon size={16} />
                <span className="station-label">{t('bootstrap.step_master_title').toUpperCase()}</span>
              </div>

              <div className="flex-col" style={{ gap: '16px' }}>
                <div className="station-form-group">
                  <label className="station-label">{t('operator.username').toUpperCase()}</label>
                  <input 
                    className="station-input" 
                    value={adminUsername} 
                    onChange={e => setAdminUsername(e.target.value)} 
                    placeholder="master"
                  />
                </div>
                <div className="station-form-group">
                  <label className="station-label">{t('operator.display_name').toUpperCase()}</label>
                  <input 
                    className="station-input" 
                    value={adminName} 
                    onChange={e => setAdminName(e.target.value)} 
                    placeholder="Ej: SISTEMAS"
                  />
                </div>
                <div className="station-form-group">
                  <label className="station-label">{t('operator.role').toUpperCase()}</label>
                  <select 
                    className="station-input" 
                    value={adminRole}
                     onChange={e => setAdminRole(e.target.value as any)}
                  >
                    <option value="ADMIN">{t('operator.roles.ADMIN')}</option>
                    <option value="TECH">{t('operator.roles.TECH')}</option>
                  </select>
                  <p style={{ fontSize: '10px', opacity: 0.5, marginTop: '4px' }}>{t('bootstrap.role_hint')}</p>
                </div>
                <div className="station-form-group">
                  <label className="station-label">{t('bootstrap.pin_label').toUpperCase()}</label>
                  <input 
                    type="password"
                    maxLength={6}
                    className="station-input" 
                    value={pin} 
                    onChange={e => setPin(e.target.value)} 
                    placeholder="****"
                    style={{ letterSpacing: '8px' }}
                  />
                </div>
                <div className="station-form-group">
                  <label className="station-label">{t('bootstrap.pin_confirm_label').toUpperCase()}</label>
                  <input 
                    type="password"
                    maxLength={6}
                    className="station-input" 
                    value={pinConfirm} 
                    onChange={e => setPinConfirm(e.target.value)} 
                    placeholder="****"
                    style={{ letterSpacing: '8px' }}
                  />
                </div>
              </div>
            </div>
          )}

          {step === 2 && (
            <div className="flex-col animate-fade-in" style={{ gap: '24px' }}>
              <div className="flex-row" style={{ gap: '8px', opacity: 0.7 }}>
                <BuildingIcon size={16} />
                <span className="station-label">{t('bootstrap.step_unit_title').toUpperCase()}</span>
              </div>

              <div className="flex-col" style={{ gap: '16px' }}>
                <div className="station-form-group">
                  <label className="station-label">{t('bootstrap.unit_code_label').toUpperCase()}</label>
                  <input 
                    className="station-input" 
                    value={unitCode} 
                    onChange={e => setUnitCode(e.target.value)} 
                    placeholder="UNIT01"
                  />
                </div>
                <div className="station-form-group">
                  <label className="station-label">{t('bootstrap.unit_name_label').toUpperCase()}</label>
                  <input 
                    className="station-input" 
                    value={unitName} 
                    onChange={e => setUnitName(e.target.value)} 
                    placeholder="Ej: DEPÓSITOS RETAIL"
                  />
                </div>
              </div>

              <div className="alert-box warning" style={{ fontSize: '11px', opacity: 0.8 }}>
                <p>⚠️ {t('bootstrap.unit_warning').toUpperCase()}</p>
              </div>
            </div>
          )}

          {error && (
            <div className="alert-box error" style={{ marginTop: '24px' }}>
              <p>{t(error)}</p>
            </div>
          )}
