        <footer className="station-modal-footer" style={{ justifyContent: 'space-between' }}>
          <div>
             <span className="station-label" style={{ opacity: 0.5 }}>{t('bootstrap.step_counter', { current: step, total: 2 }).toUpperCase()}</span>
