            {step === 1 ? (
              <button 
                className="station-btn station-btn-primary" 
                disabled={!adminName || pin.length < 4}
                onClick={() => setStep(2)}
              >
                {t('bootstrap.btn_next')}
              </button>
            ) : (
              <button 
                className="station-btn station-btn-primary" 
                disabled={!unitCode || isLoading}
                onClick={handleBootstrap}
