'use client';

import React, { useState, useEffect } from 'react';
import { useLanguage } from '@/lib/context/LanguageContext';
import { useWorkspace } from '@/lib/context/WorkspaceContext';
import { coreDb } from '@/lib/db/SystemDB';
import { Operator, WorkspaceUnit } from '@/lib/types/auth.types';
import { ShieldIcon, UserIcon, BuildingIcon, XIcon, DeleteIcon, CheckIcon, KeyIcon, ShieldCheckIcon } from '../common/Icons';

export const LoginScreen: React.FC = () => {
  const { t } = useLanguage();
  const { login, verifyMfa, selectUnit, currentOperator, logout, isLocked, unlockSession, installationKey } = useWorkspace();

  const [pin, setPin] = useState('');
  const [operators, setOperators] = useState<Operator[]>([]);
  const [units, setUnits] = useState<WorkspaceUnit[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [loginSuccess, setLoginSuccess] = useState(false);
  const [availableUnits, setAvailableUnits] = useState<WorkspaceUnit[]>([]);
  const [mfaPhase, setMfaPhase] = useState(false);
  const [mfaToken, setMfaToken] = useState('');

  useEffect(() => {
    const loadOps = async () => {
      try {
        if (!coreDb.isOpen()) await coreDb.open();
        const allOps = (await coreDb.operators.toArray()).filter(o => o.isActive);
        setOperators(allOps);
        const allUnits = (await coreDb.units.toArray()).filter(u => u.isActive);
        setUnits(allUnits);
      } catch (err) {
        console.error('[ABDFN-AUTH] Metadata load failed', err);
      }
    };
    loadOps();
  }, []);

  useEffect(() => {
    if (currentOperator && currentOperator.unitIds.length > 1) {
      const filtered = units.filter(u => currentOperator.unitIds.includes(u.id));
      setAvailableUnits(filtered);
    }
  }, [currentOperator, units]);

  const handleKeyPress = (num: string) => {
    setError(null);
    if (!mfaPhase) {
      if (pin.length < 6) setPin(prev => prev + num);
    } else {
      if (mfaToken.length < 6) setMfaToken(prev => prev + num);
    }
  };

  const handleBackspace = () => {
    if (!mfaPhase) {
      setPin(prev => prev.slice(0, -1));
    } else {
      setMfaToken(prev => prev.slice(0, -1));
    }
  };

  const handleSubmit = async () => {
    setError(null);

    if (!mfaPhase) {
      if (pin.length < 4) return;
      const result = await login(pin);
      if (result.success) {
        if (result.mfaRequired) {
          setMfaPhase(true);
        } else {
          setLoginSuccess(true);
        }
      } else {
        setError(t('auth.login.error_pin'));
        setPin('');
      }
    } else if (isLocked) {
      if (pin.length < 4) return;
      const success = await unlockSession(pin);
      if (!success) {
        setError(t('auth.login.error_pin'));
        setPin('');
      } else {
        setLoginSuccess(true);
      }
    } else {
      if (mfaToken.length < 6) return;
      const success = await verifyMfa(mfaToken);
      if (success) {
        setLoginSuccess(true);
      } else {
        setError(t('auth.mfa.invalid'));
        setMfaToken('');
      }
    }
  };


  // Physical Keyboard Support
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key >= '0' && e.key <= '9') {
        handleKeyPress(e.key);
      } else if (e.key === 'Backspace') {
        handleBackspace();
      } else if (e.key === 'Enter') {
        handleSubmit();
      } else if (e.key === 'Escape') {
        if (mfaPhase) {
          setMfaPhase(false);
          setMfaToken('');
        } else {
          setPin('');
        }
        setError(null);
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [pin, mfaPhase, mfaToken]);

  const handleUnitSelect = async (unit: WorkspaceUnit) => {
    await selectUnit(unit);
  };

  // If logged in but multi-unit, show unit selector
  if (currentOperator && currentOperator.unitIds.length > 1) {
    return (
      <div className="station-modal-overlay" style={{ background: 'var(--bg-primary)' }}>
        <div className="flex-col" style={{ gap: '40px', alignItems: 'center' }}>
              <header style={{ textAlign: 'center' }}>
                 <h1 style={{ fontSize: '2rem', letterSpacing: '4px', marginBottom: '8px' }}>{(t('auth.login.unit_selection_title') || 'SELECCIÓN DE UNIDAD').toUpperCase()}</h1>
                 <p style={{ opacity: 0.5 }}>{ (t('operator.role') || 'ROL').toUpperCase() }: { (currentOperator.displayName || currentOperator.username || 'OPERATOR').toUpperCase() }</p>
              </header>

          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(1, 1fr)', gap: '16px', width: '400px' }}>
             {availableUnits.map(unit => (
               <button 
                key={unit.id}
                className="station-btn"
                style={{ 
                  height: '80px', 
                  fontSize: '1.1rem', 
                  justifyContent: 'flex-start', 
                  padding: '0 24px',
                  border: '1px solid var(--border-primary)'
                }}
                onClick={() => handleUnitSelect(unit)}
               >
                 <BuildingIcon size={20} style={{ marginRight: '16px', opacity: 0.5 }} />
                 <div className="flex-col" style={{ alignItems: 'flex-start' }}>
                    <span style={{ fontSize: '0.8rem', opacity: 0.5 }}>[{ (unit.code || '???').toUpperCase() }]</span>
                    <span>{ (unit.name || 'UNKNOWN').toUpperCase() }</span>
                 </div>
               </button>
             ))}
          </div>

          <button className="station-btn station-btn-secondary" onClick={logout}>
            {t('auth.mfa.back_btn')}
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="station-modal-overlay" style={{ background: 'var(--bg-primary)', overflow: 'hidden' }}>
       <div style={{ 
         display: 'grid', 
         gridTemplateColumns: '1fr auto', 
         gap: '64px', 
         alignItems: 'center', 
         width: '100%', 
         maxWidth: '900px', 
         background: 'rgba(255,255,255,0.02)',
         padding: '48px',
         border: '1px solid var(--border-color)',
         borderRadius: 'var(--radius-std)',
         position: 'relative'
       }}>

          {/* Column 1: Identity & Feedback */}
          <div className="flex-col" style={{ gap: '32px', alignItems: 'center', borderRight: '1px solid var(--border-color)', paddingRight: '48px' }}>
            <header className="flex-col" style={{ alignItems: 'center', gap: '8px' }}>
               <div className="flex-row" style={{ gap: '10px', alignItems: 'center' }}>
                  <ShieldIcon size={32} color="var(--accent-primary)" />
                  <h1 style={{ fontSize: '1.4rem', fontWeight: 900, letterSpacing: '4px', margin: 0 }}>{t('ui.title')}</h1>
               </div>
               <div style={{ height: '2px', width: '100%', background: 'var(--accent-primary)', opacity: 0.2 }} />
               <p style={{ fontSize: '0.75rem', opacity: 0.4, letterSpacing: '3px', textTransform: 'uppercase', fontWeight: 'bold' }}>{t('dashboard.sys_status_online')}</p>
            </header>

            <div className="flex-col" style={{ alignItems: 'center', gap: '16px', width: '100%' }}>
               <span style={{ fontSize: '0.7rem', opacity: 0.4, fontWeight: 'bold', letterSpacing: '2px' }}>
                 {isLocked ? `[ TERMINAL_LOCKED - ${(currentOperator?.username || 'SYSTEM').toUpperCase()} ]` : mfaPhase ? `[ ${t('auth.mfa.placeholder_token')} - TOTP ]` : `[ ${t('audit.tabSecurity')} ]`}
               </span>

               {/* PIN / MFA Digit Feedback */}
               <div className="flex-row" style={{ gap: '12px', height: '50px', alignItems: 'center', justifyContent: 'center' }}>
                  {!mfaPhase ? (
                    pin.length === 0 ? (
                      <span style={{ opacity: 0.2, fontSize: '0.75rem', letterSpacing: '4px' }}>{t('auth.login.placeholder_pin')}</span>
                    ) : (
                      pin.split('').map((_, idx) => (
                        <div key={`pin-${idx}`} className="flex-center" style={{ width: '32px', height: '48px', borderBottom: '3px solid var(--accent-primary)', fontSize: '2rem', color: 'var(--accent-primary)', transform: 'translateY(-2px)', animation: 'fadeIn 0.2s ease-out' }}>*</div>
                      ))
                    )
                  ) : (
                    mfaToken.length === 0 ? (
                      <span style={{ opacity: 0.2, fontSize: '0.75rem', letterSpacing: '4px' }}>{t('auth.mfa.placeholder_token')}</span>
                    ) : (
                      mfaToken.split('').map((char, idx) => (
                        <div key={`mfa-${idx}`} className="flex-center" style={{ width: '32px', height: '48px', borderBottom: '3px solid var(--accent-secondary)', fontSize: '2rem', color: 'var(--accent-secondary)', transform: 'translateY(-2px)', animation: 'fadeIn 0.2s ease-out' }}>
                          {char}
                        </div>
                      ))
                    )
                  )}
               </div>

               {error && (
                 <div className="alert-box error animate-fade-in" style={{ padding: '8px 16px', fontSize: '0.8rem', width: '100%', textAlign: 'center' }}>
                   <span>{error}</span>
                 </div>
               )}
            </div>

            {/* Technical mode hint */}
            {!mfaPhase && (
              <div style={{ marginTop: '12px' }}>
                <button 
                  className="station-btn" 
                  style={{ border: 'none', background: 'transparent', opacity: 0.4, fontSize: '0.65rem', fontWeight: 'bold' }}
                  onDoubleClick={() => window.dispatchEvent(new KeyboardEvent('keydown', { ctrlKey: true, shiftKey: true, key: 'F12' }))}
                >
                    <KeyIcon size={12} style={{ marginRight: '6px' }} />
                    {t('auth.login.technical_mode')}
                </button>
              </div>
            )}

            {isLocked && (
               <button 
                className="station-btn" 
                style={{ marginTop: '12px', border: 'none', background: 'transparent', opacity: 0.5, fontSize: '0.75rem' }}
                onClick={logout}
              >
                {t('auth.login.switch_user')}
              </button>
            )}
            {mfaPhase && (
              <button 
                className="station-btn" 
                style={{ marginTop: '12px', border: 'none', background: 'transparent', opacity: 0.5, fontSize: '0.75rem' }}
                onClick={() => { setMfaPhase(false); setMfaToken(''); setError(null); }}
              >
                {t('auth.mfa.back_btn')}
              </button>
            )}

            {!installationKey && (
              <div 
                className="alert-box warning animate-pulse" 
                style={{ marginTop: '24px', fontSize: '0.65rem', padding: '12px', border: '1px dashed var(--status-warn)' }}
              >
                <div className="flex-row" style={{ gap: '8px', alignItems: 'center', marginBottom: '4px' }}>
                   <KeyIcon size={12} />
                   <strong>SECURITY_ENGINE_LOCKED</strong>
                </div>
                <span>{t('auth.login.master_required_hint')}</span>
              </div>
            )}
          </div>

          {/* Column 2: Control Panel (Numpad) */}
          <div className="flex-col" style={{ alignItems: 'center', gap: '24px' }}>
             <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '12px' }}>
                {['1', '2', '3', '4', '5', '6', '7', '8', '9'].map(n => (
                  <button 
                    key={n} 
                    className="station-btn" 
                    style={{ width: '70px', height: '70px', fontSize: '1.4rem', borderRadius: '50%', padding: 0 }}
                    onClick={() => handleKeyPress(n)}
                  >
                    {n}
                  </button>
                ))}
                <button 
                  className="station-btn" 
                  style={{ width: '70px', height: '70px', borderRadius: '50%', background: 'transparent', border: 'none', padding: 0 }}
                  onClick={() => { setPin(''); setError(null); }} 
                >
                  <XIcon size={20} style={{ opacity: 0.5 }} />
                </button>
                <button 
                  className="station-btn" 
                  style={{ width: '70px', height: '70px', fontSize: '1.4rem', borderRadius: '50%', padding: 0 }}
                  onClick={() => handleKeyPress('0')}
                >
                  0
                </button>
                <button 
                  className="station-btn" 
                  style={{ width: '70px', height: '70px', borderRadius: '50%', background: 'transparent', border: 'none', padding: 0 }}
                  onClick={handleBackspace}
                >
                  <DeleteIcon size={20} style={{ opacity: 0.5 }} />
                </button>
             </div>

             <button 
                className={`station-btn ${mfaPhase ? 'primary-secondary' : 'primary'} large`}
                style={{ width: '100%', height: '56px', fontSize: '1rem', letterSpacing: '2px', gap: '12px' }}
                onClick={handleSubmit}
             >
                {mfaPhase ? <ShieldCheckIcon size={20} /> : <CheckIcon size={20} />}
                {isLocked ? (t('auth.login.unlock_btn')) : mfaPhase ? (t('auth.mfa.verify_btn')) : (t('auth.login.access_btn'))}
             </button>
          </div>
       </div>

       {/* Floating Industrial Status */}
       <div className="station-integrity-badge" style={{ position: 'fixed', bottom: '24px', right: '24px', pointerEvents: 'none' }}>
         <div className="integrity-dot" />
         <span>{t('ui.title')} v6.0.0</span>
       </div>
    </div>
  );
};

'use client';

import React, { useState, useEffect } from 'react';
import { useWorkspace } from '@/lib/context/WorkspaceContext';
import { useLanguage } from '@/lib/context/LanguageContext';
import { 
  ShieldAlertIcon, 
  XIcon, 
  CheckIcon, 
  DeleteIcon,
  ZapIcon,
  ShieldCheckIcon,
  RefreshCwIcon
} from '@/components/common/Icons';
import { generateTotpSecret } from '@/lib/utils/mfa.utils';
import { coreDb } from '@/lib/db/SystemDB';

export const StepUpAuthModal: React.FC = () => {
  const { 
    isStepUpDialogOpen, 
    setIsStepUpDialogOpen, 
    pendingStepUpLevel, 
    currentOperator,
    verifyMfa 
  } = useWorkspace();
  const { t } = useLanguage();

  const [token, setToken] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [isVerifying, setIsVerifying] = useState(false);

  // Enrollment state
  const [isEnrolling, setIsEnrolling] = useState(false);
  const [tempSecret, setTempSecret] = useState<string | null>(null);

  useEffect(() => {
    if (isStepUpDialogOpen) {
      setToken('');
      setError(null);

      // Force enrollment check
      if (currentOperator && !currentOperator.mfaEnabled) {
        setIsEnrolling(true);
        const secret = generateTotpSecret();
        setTempSecret(secret);

        // Update operator in memory (not DB yet, only on successful verification)
        // Note: verifyMfa in WorkspaceContext will handle the DB update on success.
        // But it needs the secret to check the token.
        // Temporary override for verification:
        currentOperator.mfaSecret = secret;
      } else {
        setIsEnrolling(false);
        setTempSecret(null);
      }
    }
  }, [isStepUpDialogOpen, currentOperator]);

  if (!isStepUpDialogOpen) return null;

  const handleKeyPress = (num: string) => {
    if (token.length < 6) {
      setToken(prev => prev + num);
      setError(null);
    }
  };

  const handleBackspace = () => {
    setToken(prev => prev.slice(0, -1));
  };

  const handleSubmit = async () => {
    if (token.length < 6) return;
    setIsVerifying(true);
    setError(null);

    try {
      const success = await verifyMfa(token);
      if (!success) {
        setError(t('auth.mfa.invalid') || 'Token inválido');
        setToken('');
      }
    } catch (err) {
      setError('Error de verificación');
    } finally {
      setIsVerifying(false);
    }
  };

  const handleCancel = () => {
    setIsStepUpDialogOpen(false);
    // Ideally we'd resolve the pending promise to false here, 
    // but verifyMfa handles success. We need a way to reject/resolve false.
    // In WorkspaceContext, we should handle the modal close as a failure if it's still pending.
    // (WorkspaceContext has the resolver logic).
  };

  return (
    <div className="station-modal-overlay animate-fade-in" style={{ zIndex: 9999 }}>
      <div className="station-modal" style={{ maxWidth: '760px', background: 'var(--bg-primary)' }}>

        <header className="station-modal-header technical-header-small">
           <div className="flex-row" style={{ gap: '12px', alignItems: 'center' }}>
              <ShieldAlertIcon size={16} color={isEnrolling ? "var(--status-warn)" : "var(--accent-primary)"} />
              <span style={{ fontSize: '0.75rem', fontWeight: 900, letterSpacing: '2px', opacity: 0.5 }}>
                {isEnrolling ? 'MFA_ENROLLMENT' : 'SECURITY_VERIFICATION'}
              </span>
           </div>
           <button onClick={handleCancel} className="station-btn secondary tiny">
              <span style={{ fontSize: '0.65rem' }}>ESC</span>
           </button>
        </header>        <div className="station-modal-content" style={{ padding: '0', overflow: 'hidden' }}>
          <div style={{ display: 'grid', gridTemplateColumns: 'minmax(300px, 1fr) auto', minHeight: '400px' }}>

            {/* Column 1: Technical Info & Secret */}
            <div className="flex-col" style={{ 
              padding: '32px', 
              gap: '24px', 
              background: 'rgba(0,0,0,0.1)',
              borderRight: '1px solid var(--border-color)'
            }}>
              <header className="flex-col" style={{ gap: '8px' }}>
                <h2 style={{ fontSize: '1.1rem', margin: 0, letterSpacing: '2px', fontWeight: 900 }}>
                  {isEnrolling ? 'ENROLAMIENTO MFA' : 'VERIFICACIÓN'}
                </h2>
                <div style={{ height: '2px', width: '32px', background: 'var(--accent-primary)', opacity: 0.5 }} />
                <p style={{ fontSize: '0.65rem', opacity: 0.5, margin: 0, textTransform: 'uppercase', letterSpacing: '1px', fontWeight: 'bold' }}>
                  Nivel de Autorización: {pendingStepUpLevel}
                </p>
              </header>

              {isEnrolling && tempSecret ? (
                <div className="alert-box warning" style={{ 
                  fontSize: '0.75rem', 
                  background: 'rgba(255,157,0,0.02)', 
                  border: '1px solid var(--status-warn)',
                  padding: '20px',
                  borderRadius: '2px'
                }}>
                   <p style={{ margin: '0 0 16px 0', opacity: 0.8, fontWeight: 'bold' }}>Vincule su aplicación mediante esta clave manual:</p>
                   <div style={{ 
                     background: 'var(--bg-color)', 
                     padding: '16px', 
                     fontSize: '1rem', 
                     fontFamily: 'var(--font-mono)', 
                     textAlign: 'center', 
                     letterSpacing: '3px',
                     border: '1px solid var(--border-color)',
                     color: 'var(--status-warn)',
                     fontWeight: 900,
                     wordBreak: 'break-all'
                   }}>
                     {tempSecret.match(/.{1,4}/g)?.join(' ')}
                   </div>
                   <p style={{ margin: '16px 0 0 0', opacity: 0.5, fontSize: '0.7rem', lineHeight: '1.4' }}>
                     Introduzca el código de 6 dígitos generado tras sincronizar su dispositivo (Google Auth / Authy).
                   </p>
                </div>
              ) : (
                <div style={{ flex: 1, display: 'flex', alignItems: 'center' }}>
                  <p style={{ fontSize: '0.8rem', opacity: 0.6, lineHeight: '1.6' }}>
                    Esta operación requiere un factor de autenticación adicional. El código TOTP generado en su dispositivo es necesario para validar su identidad.
                  </p>
                </div>
              )}
            </div>

            {/* Column 2: Operation & Numpad */}
            <div className="flex-col" style={{ padding: '32px', gap: '32px', alignItems: 'center', background: 'var(--bg-primary)' }}>
              {/* Token Display Integration */}
              <div className="flex-col" style={{ gap: '12px', alignItems: 'center' }}>
                <span style={{ fontSize: '0.6rem', opacity: 0.4, fontWeight: 'bold', letterSpacing: '2px' }}>[ TOKEN_INPUT_BUFFER ]</span>
                <div className="flex-row" style={{ gap: '10px' }}>
                  {[0,1,2,3,4,5].map(i => (
                    <div 
                      key={i} 
                      className="flex-center"
                      style={{ 
                        width: '32px', 
                        height: '40px', 
                        borderBottom: `3px solid ${token.length > i ? (isEnrolling ? 'var(--status-warn)' : 'var(--accent-primary)') : 'var(--border-color)'}`,
                        fontSize: '1.4rem',
                        fontFamily: 'var(--font-mono)',
                        fontWeight: 900,
                        opacity: token.length > i ? 1 : 0.1
                      }}
                    >
                      {token[i] || '0'}
                    </div>
                  ))}
                </div>
                {error && <p style={{ color: 'var(--error)', fontSize: '0.7rem', margin: '4px 0 0 0', fontWeight: 'bold' }}>{error}</p>}
              </div>

              {/* Numpad Circles */}
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '12px' }}>
                {['1', '2', '3', '4', '5', '6', '7', '8', '9', 'X', '0', 'DEL'].map(val => (
                  <button
                    key={val}
                    className="station-btn"
                    style={{ 
                      width: '60px', 
                      height: '60px', 
                      padding: 0, 
                      fontSize: '1.1rem', 
                      borderRadius: '50%',
                      background: val === 'X' || val === 'DEL' ? 'transparent' : 'var(--surface-color)',
                      border: val === 'X' || val === 'DEL' ? 'none' : '1px solid var(--border-color)',
                      boxShadow: 'none'
                    }}
                    onClick={() => {
                      if (val === 'X') setToken('');
                      else if (val === 'DEL') handleBackspace();
                      else handleKeyPress(val);
                    }}
                  >
                    {val === 'DEL' ? <DeleteIcon size={18} style={{ opacity: 0.5 }} /> : val === 'X' ? <XIcon size={18} style={{ opacity: 0.5 }} /> : val}
                  </button>
                ))}
              </div>
            </div>
          </div>
        </div>

        <footer className="station-modal-footer" style={{ gap: '16px' }}>
          <button className="station-btn secondary small" style={{ minWidth: '120px' }} onClick={handleCancel}>
            {t('common.cancel').toUpperCase()}
          </button>
          <div style={{ flex: 1 }} />
          <button 
            className={`station-btn ${isEnrolling ? 'primary-secondary' : 'primary'} small`} 
            style={{ minWidth: '160px' }} 
            disabled={token.length < 6 || isVerifying}
            onClick={handleSubmit}
          >
            {isVerifying ? <RefreshCwIcon size={18} className="spin" /> : <CheckIcon size={18} />}
            <span style={{ marginLeft: '8px' }}>{isEnrolling ? 'ENROLAR' : 'VERIFICAR'}</span>
          </button>
        </footer>
      </div>
      <style jsx>{`
        .obsidian-depth {
          animation: slideUp 0.3s cubic-bezier(0.16, 1, 0.3, 1);
        }
        @keyframes slideUp {
          from { transform: translateY(20px); opacity: 0; }
          to { transform: translateY(0); opacity: 1; }
        }
        @keyframes fadeIn {
          from { opacity: 0; }
          to { opacity: 1; }
        }
      `}</style>
    </div>
  );
};

