           <button className="station-btn" onClick={onClose}>{t('common.cancel').toUpperCase()}</button>
           <button className="station-btn station-btn-primary" onClick={() => onSave(formData)}>
              <SaveIcon size={16} /> {t('common.save').toUpperCase()}
           </button>
