'use client';

import React, { useState } from 'react';
import { useLanguage } from '@/lib/context/LanguageContext';
import { EtlPreset, GawebConfig } from '@/lib/types/etl.types';
import { 
  IDIOMAS_ISO, 
  FORMATOS_GAWEB, 
  SOPORTES_GAWEB, 
  DESTINOS_GAWEB, 
  INDICADORES_DESTINO, 
  METODOS_ENVIO,
  VIAS_REPARTO,
  COPIAS_PAPEL,
} from '@/lib/constants/letter.constants';
import { HelpIcon, SaveIcon, XIcon, AlertTriangleIcon } from '@/components/common/Icons';

interface PresetEditorModalProps {
  preset: EtlPreset | null;
  onSave: (p: EtlPreset) => void;
  onClose: () => void;
}

const DEFAULT_CONFIG: GawebConfig = {
  active: true,
  tipoSoporte: 'PDF',
  formatoCarta: '04',
  forzarMetodo: ' ',
  indicadorDestino: '0',
  tipoDestino: 'CL',
  codigoEntorno: 'ABDFN01',
  codigoDocumento: 'X00000',
  fechaGeneracion: new Date().toISOString().split('T')[0].replace(/-/g, ''),
  fechaCarta: new Date().toISOString().split('T')[0].replace(/-/g, ''),
  oficina: '00000',
  paginasDefecto: 4,
  idioma: '  ',
  viaReparto: '  ',
  copiaPapel: ' '
};

const PresetEditorModal: React.FC<PresetEditorModalProps> = ({ preset, onSave, onClose }) => {
  const { t } = useLanguage();

  const [formData, setFormData] = useState<EtlPreset>(preset || {
    name: '',
    version: '1.0',
    description: '',
    chunkSize: 1000,
    encoding: 'utf-8',
    recordTypeStart: 0,
    recordTypeLen: 2,
    defaultRecordType: 'DATA',
    headerTypeId: 'H',
    recordTypes: [],
    isActive: true,
    gawebConfig: DEFAULT_CONFIG,
    createdAt: Date.now(),
    updatedAt: Date.now()
  });

  const [helpTopic, setHelpTopic] = useState<{title: string, content: string} | null>(null);
  const [errors, setErrors] = useState<Record<string, string>>({});

  const updateGaweb = (field: keyof GawebConfig, value: any) => {
    setFormData({
      ...formData,
      gawebConfig: {
        ...(formData.gawebConfig || DEFAULT_CONFIG),
        [field]: value
      }
    });
  };

  const validate = (): boolean => {
    const newErrors: Record<string, string> = {};
    const config = formData.gawebConfig || DEFAULT_CONFIG;

    if (!formData.name) newErrors.name = 'Nombre requerido';
    if (config.codigoDocumento.length !== 6) newErrors.codDoc = 'Exacto 6 caracteres';
    if (config.oficina.length !== 5) newErrors.oficina = 'Exacto 5 caracteres';

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const currentSoporte = formData.gawebConfig?.tipoSoporte || 'PDF';
  const filteredFormatos = FORMATOS_GAWEB.filter(f => f.extra === currentSoporte);

  const renderField = (label: string, helpKey: string | null, children: React.ReactNode, errorKey?: string) => (
    <div className="station-form-field">
      <div className="flex-row" style={{ alignItems: 'center', gap: '8px' }}>
        <label className="station-label">{label}</label>
        {helpKey && (
          <button 
            type="button"
            className="station-help-btn"
            onClick={() => setHelpTopic({ title: label, content: t(`letter.help.${helpKey}`) })}
          >
            ?
          </button>
        )}
      </div>
      {children}
      {errorKey && errors[errorKey] && (
        <span className="txt-err" style={{ fontSize: '0.7rem', fontWeight: 900 }}>{errors[errorKey].toUpperCase()}</span>
      )}
    </div>
  );

  return (
    <div className="station-modal-overlay" onClick={onClose}>
      <div 
        className="station-modal" 
        style={{ maxWidth: '900px' }}
        onClick={e => e.stopPropagation()}
      >
        <header className="station-modal-header">
          <h2 className="station-registry-item-name" style={{ fontSize: '1rem' }}>{t('letter.config_title')}</h2>
          <button className="station-btn" style={{ border: 'none', padding: '4px' }} onClick={onClose}>
            <XIcon size={20} />
          </button>
        </header>

        <div className="station-modal-content" style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '24px' }}>

          <div className="flex-col" style={{ gap: '20px' }}>
            <span className="station-form-section-title">IDENTIFICACIÓN</span>
            <section className="station-card flex-col" style={{ gap: '16px' }}>
              {renderField('Nombre del Preset', null, 
                <input 
                  className="station-input" 
                  value={formData.name} 
                  placeholder="Ej: CARTAS_ORDINARIAS"
                  onChange={e => setFormData({...formData, name: e.target.value})} 
                />, 'name')}
              {renderField('Descripción', null,
                <input 
                  className="station-input" 
                  value={formData.description} 
                  onChange={e => setFormData({...formData, description: e.target.value})} 
                />)}
              <div className="station-checkbox-group" style={{ marginTop: '8px' }}>
                <input 
                  type="checkbox" 
                  id="chk-active"
                  className="station-checkbox"
                  checked={formData.isActive} 
                  onChange={e => setFormData({...formData, isActive: e.target.checked})} 
                />
                <label htmlFor="chk-active" className="station-label" style={{ margin: 0, cursor: 'pointer' }}>Visible para los operadores</label>
              </div>
            </section>

            <span className="station-form-section-title" style={{ marginTop: '12px' }}>CONFIGURACIÓN TÉCNICA</span>
            <section className="station-card flex-col" style={{ gap: '16px' }}>
              {renderField('Tipo Soporte', null,
                <select className="station-select" value={formData.gawebConfig?.tipoSoporte} onChange={e => updateGaweb('tipoSoporte', e.target.value)}>
                  {SOPORTES_GAWEB.map(s => <option key={s.globalId} value={s.globalId}>{s.label}</option>)}
                </select>)}

              {renderField('Formato GAWEB', 'formato',
                <select className="station-select" value={formData.gawebConfig?.formatoCarta} onChange={e => updateGaweb('formatoCarta', e.target.value)}>
                  {filteredFormatos.map(f => <option key={f.globalId} value={f.globalId}>{f.label}</option>)}
                </select>)}

              {renderField('Método de Envío', null,
                <select className="station-select" value={formData.gawebConfig?.forzarMetodo} onChange={e => updateGaweb('forzarMetodo', e.target.value)}>
                  {METODOS_ENVIO.map(m => <option key={m.globalId} value={m.globalId}>{m.label}</option>)}
                </select>)}
            </section>
          </div>

          <div className="flex-col" style={{ gap: '20px' }}>
            <span className="station-form-section-title">SEGMENTACIÓN Y HOST</span>
            <section className="station-card flex-col" style={{ gap: '16px' }}>
              <div className="station-form-grid">
                {renderField('Tipo Destinatario', null,
                  <select className="station-select" value={formData.gawebConfig?.tipoDestino} onChange={e => updateGaweb('tipoDestino', e.target.value)}>
                    {DESTINOS_GAWEB.map(d => <option key={d.globalId} value={d.globalId}>{d.label}</option>)}
                  </select>)}
                {renderField('Indicador Destino', null,
                  <select className="station-select" value={formData.gawebConfig?.indicadorDestino} onChange={e => updateGaweb('indicadorDestino', e.target.value)}>
                    {INDICADORES_DESTINO.map(i => <option key={i.globalId} value={i.globalId}>{i.label}</option>)}
                  </select>)}
              </div>

              {renderField('Entorno Host', 'entorno',
                <input className="station-input" value={formData.gawebConfig?.codigoEntorno} onChange={e => updateGaweb('codigoEntorno', e.target.value)} />)}

              <div className="station-form-grid">
                {renderField('F. Generación (Default)', 'fechas',
                  <input className="station-input" value={formData.gawebConfig?.fechaGeneracion} onChange={e => updateGaweb('fechaGeneracion', e.target.value.replace(/\D/g, ''))} />)}
                {renderField('F. Carta (Default)', 'fechas',
                  <input className="station-input" value={formData.gawebConfig?.fechaCarta} onChange={e => updateGaweb('fechaCarta', e.target.value.replace(/\D/g, ''))} />)}
              </div>
            </section>

            <span className="station-form-section-title" style={{ marginTop: '12px' }}>OPCIONALES GAWEB</span>
            <section className="station-card flex-col" style={{ gap: '16px' }}>
              <div className="station-form-grid">
                {renderField('Idioma (ISO)', 'idioma',
                  <select className="station-select" value={formData.gawebConfig?.idioma} onChange={e => updateGaweb('idioma', e.target.value)}>
                    {IDIOMAS_ISO.map(i => <option key={i.globalId} value={i.globalId}>{i.label}</option>)}
                  </select>)}
                {renderField('Vía Reparto', 'viaReparto',
                  <select className="station-select" value={formData.gawebConfig?.viaReparto} onChange={e => updateGaweb('viaReparto', e.target.value)}>
                    {VIAS_REPARTO.map(v => <option key={v.globalId} value={v.globalId}>{v.label}</option>)}
                  </select>)}
              </div>

              <div className="station-form-grid">
                 {renderField('Cód. Doc', 'codDoc',
                   <input className="station-input" maxLength={6} value={formData.gawebConfig?.codigoDocumento} onChange={e => updateGaweb('codigoDocumento', e.target.value.toUpperCase())} />, 'codDoc')}
                 {renderField('Oficina', 'oficina',
                   <input className="station-input" maxLength={5} value={formData.gawebConfig?.oficina} onChange={e => updateGaweb('oficina', e.target.value.replace(/\D/g, ''))} />, 'oficina')}
                 {renderField('Páginas', 'paginas',
                   <input className="station-input" type="number" value={formData.gawebConfig?.paginasDefecto} onChange={e => updateGaweb('paginasDefecto', Number(e.target.value))} />)}
              </div>
            </section>
          </div>

        </div>

        <footer className="station-modal-footer">
          <button className="station-btn" onClick={onClose}>Cancelar</button>
          <button className="station-btn station-btn-primary" onClick={() => validate() && onSave(formData)}>
            <SaveIcon size={16} /> GUARDAR CONFIGURACIÓN
          </button>
        </footer>

        {helpTopic && (
          <div className="station-modal-overlay" style={{ zIndex: 6000 }} onClick={() => setHelpTopic(null)}>
             <div className="station-modal" style={{ maxWidth: '450px' }} onClick={e => e.stopPropagation()}>
                <header style={{ paddingBottom: '16px', borderBottom: '1px solid var(--border-color)', marginBottom: '16px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                   <span style={{ fontWeight: 800, fontSize: '0.9rem' }}>AYUDA / {helpTopic.title}</span>
                   <button className="station-btn" style={{ border: 'none', padding: '4px' }} onClick={() => setHelpTopic(null)}>X</button>
                </header>
                <div style={{ fontSize: '0.9rem', opacity: 0.8, lineHeight: '1.5' }}>
                   {helpTopic.content}
                </div>
                <button 
                  className="station-btn station-btn-primary" 
                  style={{ marginTop: '24px', width: '100%' }} 
                  onClick={() => setHelpTopic(null)}
                >
                  Entendido
                </button>
             </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default PresetEditorModal;

'use client';

import React, { useState, useEffect } from 'react';
import { useLanguage } from '@/lib/context/LanguageContext';
import { useWorkspace } from '@/lib/context/WorkspaceContext';
import { ForbiddenPanel } from '@/components/common/ForbiddenPanel';
import { useLiveQuery } from 'dexie-react-hooks';
import { db } from '@/lib/db/db';
import { LetterTemplate, TemplateComposition } from '@/lib/types/letter.types';
import JSZip from 'jszip';
import { TrashIcon, CogIcon, FileTextIcon, SaveIcon, ArrowUpIcon, ArrowDownIcon, ListIcon, EyeIcon, DownloadIcon, UploadIcon, RefreshCwIcon, XIcon, UndoIcon } from '@/components/common/Icons';

const DEFAULT_COMPOSITION: TemplateComposition = {
  fontFamily: 'Space Mono',
  fontSize: 11,
  windowX: 20,
  windowY: 45,
  windowWidth: 90,
  windowHeight: 40,
  marginTop: 20,
  marginBottom: 20,
  marginLeft: 20,
  marginRight: 20,
  headerHtml: '<div style="font-weight: 800; border-bottom: 1px solid #ccc; padding-bottom: 5px;">ABDFN UNIFIED SUITE - DEPARTAMENTO TÉCNICO</div>',
  footerHtml: '<div style="font-size: 10px; border-top: 1px solid #ccc; padding-top: 5px;">Calle Falsa 123, 28001 Madrid | www.abdfn-suite.com</div>'
};

interface TemplateEditorProps {
  canEdit?: boolean;
}

const TemplateEditor: React.FC<TemplateEditorProps> = ({ canEdit = true }) => {
  const { t } = useLanguage();
  const templates = useLiveQuery(() => db.lettertemplates_v6.toArray()) || [];

  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<'content' | 'composition'>('content');
  const [isRegistryExpanded, setIsRegistryExpanded] = useState(true);

  // Edit State
  const [editName, setEditName] = useState('');
  const [editContent, setEditContent] = useState('');
  const [editVersion, setEditVersion] = useState('1.0');
  const [editActive, setEditActive] = useState(true);
  const [docxPreview, setDocxPreview] = useState<string>('');
  const [docxTags, setDocxTags] = useState<string[]>([]);
  const [isLoadingDocx, setIsLoadingDocx] = useState(false);
  const [editConfig, setEditConfig] = useState<TemplateComposition>(DEFAULT_COMPOSITION);

  // UI State
  const [showSettingsModal, setShowSettingsModal] = useState(false);
  const [showPreview, setShowPreview] = useState(false);
  const [undoStack, setUndoStack] = useState<string[]>([]);

  const currentTemplate = templates.find(t => t.id === selectedId);

  useEffect(() => {
    if (selectedId) {
      const tmpl = templates.find(t => t.id === selectedId);
      if (tmpl) {
        setEditName(tmpl.name);
        setEditContent(tmpl.content || '');
        setEditVersion(tmpl.version || '1.0');
        setEditActive(tmpl.isActive !== false);
        setEditConfig(tmpl.config || DEFAULT_COMPOSITION);
      }
    }
  }, [selectedId, templates]);

  const recordSnapshot = () => {
    const tmpl = templates.find(t => t.id === selectedId);
    if (tmpl) setUndoStack(prev => [...prev.slice(-19), JSON.stringify(tmpl)]);
  };

  const undo = () => {
    if (undoStack.length === 0) return;
    const last = undoStack[undoStack.length - 1];
    const data = JSON.parse(last);
    setUndoStack(prev => prev.slice(0, -1));
    setEditName(data.name);
    setEditContent(data.content);
    setEditVersion(data.version);
    setEditActive(data.isActive);
    setEditConfig(data.config);
  };

  const handleCreate = async () => {
    const name = `TEMPLATE_${templates.length + 1}`;

    const id = await db.lettertemplates_v6.add({
      name,
      type: 'HTML',
      content: '<h1>TITLE</h1>\n<p>Dear {{NAME}}:</p>\n<p>Message content here...</p>\n<p>Regards,</p>',
      config: DEFAULT_COMPOSITION,
      updatedAt: Date.now()
    });
    setSelectedId(id as string);
    setActiveTab('content');
    setIsRegistryExpanded(false); // Auto-collapse to focus on editing
  };

  useEffect(() => {
    const extractDocx = async () => {
      if (currentTemplate?.type === 'DOCX' && currentTemplate.binaryContent) {
        setIsLoadingDocx(true);
        try {
          const zip = await JSZip.loadAsync(currentTemplate.binaryContent);

          // 1. Scan ALL XML files for Tags (Main, Headers, Footers)
          const tags: string[] = [];
          const tagRegex = /\{\{(.*?)\}\}/g;

          const xmlFiles = Object.keys(zip.files).filter(name => name.endsWith('.xml'));

          for (const name of xmlFiles) {
             const content = await zip.file(name)?.async('text');
             if (content) {
                let match;
                while ((match = tagRegex.exec(content)) !== null) {
                  // Clean tags from XML markers (Docxtemplater standard)
                  const tag = match[1].trim().replace(/<[^>]*>?/gm, '');
                  if (tag) tags.push(tag);
                }
             }
          }
          setDocxTags(Array.from(new Set(tags)));

          // 2. Extract Main Content Text Preview
          const docXml = await zip.file('word/document.xml')?.async('text');
          if (docXml) {
             const text = docXml
               .replace(/<w:p(?:\s+[^>]*)?>/g, '\n')
               .replace(/<[^>]*>/g, '')
               .replace(/\n\s*\n/g, '\n\n')
               .trim();
             setDocxPreview(text);
          }
        } catch (err) {
          setDocxPreview('ERR: Extraction failed.');
        } finally {
          setIsLoadingDocx(false);
        }
      } else {
        setDocxPreview('');
        setDocxTags([]);
      }
    };
    extractDocx();
  }, [selectedId, currentTemplate?.binaryContent]);

  const handleImport = async () => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = '.json';
    input.onchange = async (e: any) => {
      const file = e.target.files[0];
      if (file) {
        try {
          const text = await file.text();
          const data = JSON.parse(text);
          if (data.type === 'abdfn_template' && data.payload) {
            const id = await db.lettertemplates_v6.add({
              ...data.payload,
              name: data.name + '_IMPORTED',
              type: 'HTML',
              updatedAt: Date.now()
            });
            setSelectedId(id as string);
            setIsRegistryExpanded(false);
          }
        } catch (err) {}
      }
    };
    input.click();
  };

  const handleSave = async () => {
    if (!selectedId) return;
    recordSnapshot();
    await db.lettertemplates_v6.update(selectedId, {
      name: editName,
      content: editContent,
      config: editConfig,
      version: editVersion,
      isActive: editActive,
      updatedAt: Date.now()
    });
    // Visual feedback 
  };

  const handleDelete = async (id: string) => {
    if (!confirm(t('common.confirm_delete').toUpperCase())) return;
    await db.lettertemplates_v6.delete(id);
    if (selectedId === id) setSelectedId(null);
  };

  const handleDownload = (tmpl: LetterTemplate) => {
    const exportData = {
      type: 'abdfn_template',
      payload: tmpl,
      exportedAt: Date.now()
    };
    const blob = new Blob([JSON.stringify(exportData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${tmpl.name.toUpperCase()}_TEMPLATE.json`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const handleExportAll = async () => {
    const data = await db.lettertemplates_v6.toArray();
    const exportPath = {
      type: 'abdfn_templates_backup',
      payload: data,
      exportedAt: Date.now()
    };
    const blob = new Blob([JSON.stringify(exportPath, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `ABDFN_TEMPLATES_${new Date().toISOString().split('T')[0]}.json`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const updateConfig = (key: keyof TemplateComposition, val: any) => {
    setEditConfig(prev => ({ ...prev, [key]: val }));
  };

  return (
    <div className="flex-col" style={{ gap: '24px' }}>
      <section className="station-registry">
        <div className="station-registry-header" onClick={() => setIsRegistryExpanded(!isRegistryExpanded)}>
          <div className="station-registry-title">
            <ListIcon size={18} />
             {t('letter.templates').toUpperCase()} ({templates.length})
          </div>
          {isRegistryExpanded ? <ArrowUpIcon size={20} /> : <ArrowDownIcon size={20} />}
        </div>

        <div className={`station-registry-anim-container ${isRegistryExpanded ? 'expanded' : ''}`}>
          <div className="station-registry-anim-content">
            <div className="station-registry-content">
                <div className="station-registry-actions" style={{ justifyContent: 'space-between' }}>
                   <div className="flex-row" style={{ gap: '8px' }}>
                     <button className="station-btn" onClick={handleExportAll}><DownloadIcon size={14} /> JSON↓</button>
                     <button className="station-btn" onClick={handleImport} disabled={!canEdit}><UploadIcon size={14} /> ALL↑</button>
                   </div>
                   <button className="station-btn station-btn-primary" onClick={handleCreate} disabled={!canEdit} style={{ flex: 1, maxWidth: '300px' }}>{t('letter.ui.upload').toUpperCase()}</button>
                </div>

                <div className="flex-col" style={{ gap: '8px' }}>
                <div className="station-registry-list">
                  {templates.length === 0 && (
                    <div className="station-empty-state" style={{ minHeight: '120px' }}>
                      <span className="station-shimmer-text">{t('processor.empty').toUpperCase()}</span>
                    </div>
                  )}
                  {templates.map(tmpl => (
                    <div 
                      key={tmpl.id} 
                      className={`station-registry-item ${selectedId === tmpl.id ? 'active' : ''}`}
                      onClick={() => {
                        setSelectedId(tmpl.id!);
                        setIsRegistryExpanded(false);
                      }}
                    >
                      <div className="station-registry-item-left">
                         <div className="station-registry-item-icon"><FileTextIcon size={16} /></div>
                         <div className="station-registry-item-info">
                             <span className="station-registry-item-name">{tmpl.name}</span>
                             <span className="station-registry-item-meta">
                                V1.0 • {tmpl.type} • {new Date(tmpl.updatedAt).toLocaleDateString()}
                             </span>
                         </div>
                      </div>

                      <div className="station-registry-item-actions">
                         <button 
                           className="station-registry-action-btn"
                           onClick={(e) => { e.stopPropagation(); handleDownload(tmpl); }}
                           title="Descargar Plantilla"
                         >
                           <DownloadIcon size={16} />
                         </button>
                         {canEdit && (
                           <button 
                            className="station-registry-action-btn err"
                            onClick={(e) => { e.stopPropagation(); handleDelete(tmpl.id!); }}
                            title="Eliminar"
                          >
                            <TrashIcon size={16} />
                          </button>
                         )}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>

      <main className="station-main">
        {selectedId && currentTemplate?.type === 'DOCX' && (
        <div className="flex-col" style={{ gap: '24px' }}>
           <div className="station-card" style={{ background: 'rgba(56, 189, 248, 0.05)', borderLeft: '4px solid var(--primary-color)' }}>
              <div className="flex-row" style={{ alignItems: 'center', gap: '16px' }}>
                 <FileTextIcon size={32} style={{ color: 'var(--primary-color)' }} />
                 <div className="flex-col">
                    <span style={{ fontWeight: 800, fontSize: '1rem' }}>DOCX_STRUCTURE (OPENXML / ZIP)</span>
                    <span style={{ opacity: 0.6, fontSize: '0.75rem' }}>{t('letter.motor.gen_success').includes('✓') ? 'READ-ONLY' : 'TECHNICAL PREVIEW - WEB EDITING UNAVAILABLE'}</span>
                 </div>
              </div>
           </div>

           <div className="station-card shadow-lg" style={{ minHeight: '300px', display: 'flex', flexDirection: 'column' }}>
              <div className="station-panel-header">
                 <span className="station-title-main">EXTRACTED_CONTENT (DRAFT)</span>
                 <span className="station-badge station-badge-blue">READ-ONLY</span>
              </div>
              <div className="station-shell-content" style={{ flex: 1, padding: '24px', whiteSpace: 'pre-wrap', fontFamily: 'var(--font-mono)', fontSize: '0.85rem', opacity: 0.8 }}>
                 {isLoadingDocx ? (
                   <div className="station-shimmer-text">EXTRAYENDO ESTRUCTURA TÉCNICA...</div>
                 ) : (
                   <>
                     <div style={{ marginBottom: '24px', paddingBottom: '16px', borderBottom: '1px dashed rgba(255,255,255,0.1)' }}>
                        <span className="station-label">ETIQUETAS DETECTADAS:</span>
                        <div className="flex-row" style={{ flexWrap: 'wrap', gap: '8px', marginTop: '8px' }}>
                           {docxTags.length > 0 ? docxTags.map(t => (
                             <span key={t} className="station-badge station-badge-blue" style={{ fontSize: '0.65rem' }}>{`{{${t}}}`}</span>
                           )) : <span style={{ opacity: 0.5 }}>Ninguna detectada.</span>}
                        </div>
                     </div>
                     {docxPreview || 'Sin contenido de texto detectable.'}
                   </>
                 )}
                 {"\n\n[SISTEMA]: El motor industrial utilizará el archivo binario original para la generación final."}
              </div>
           </div>
        </div>
     )}

     {selectedId && currentTemplate?.type === 'HTML' && (
          <>
            <header className="station-card">
              <div className="station-panel-header" style={{ borderBottom: 'none', paddingBottom: 0, marginBottom: 0 }}>
                <div className="flex-col" style={{ gap: '4px' }}>
                  <h2 className="station-title-main" style={{ margin: 0 }}>{editName}</h2>
                  <div className="flex-row" style={{ alignItems: 'center', gap: '12px' }}>
                     <span style={{ opacity: 0.5, fontSize: '0.75rem', fontWeight: 700 }}>V{editVersion}</span>
                     <span className={`station-badge ${editActive ? 'station-badge-green' : 'station-badge-orange'}`}>
                        {editActive ? t('audit.status_ready').toUpperCase() : 'DRAFT'}
                     </span>
                  </div>
                </div>

                <div className="flex-row" style={{ gap: '12px' }}>
                  <button className="station-btn" onClick={undo} disabled={undoStack.length === 0 || !canEdit}><UndoIcon size={16} /></button>
                  <button className="station-btn" onClick={() => setShowSettingsModal(true)}>
                    <CogIcon size={16} /> {t('settings.title').toUpperCase()}
                  </button>
                  <button className={`station-btn ${showPreview ? 'active' : ''}`} onClick={() => setShowPreview(!showPreview)}>
                    <EyeIcon size={16} /> {t('letter.preview').toUpperCase()}
                  </button>
                  <button className="station-btn station-btn-primary" onClick={handleSave} disabled={!canEdit}>
                    <SaveIcon size={16} /> {t('common.save').toUpperCase()}
                  </button>
                </div>
              </div>

              <div className="station-tech-summary" style={{ marginTop: '16px' }}>
                <div className="station-tech-item"><span className="station-tech-label">Tipo:</span> {templates.find(t=>t.id===selectedId)?.type}</div>
                <div className="station-tech-item"><span className="station-tech-label">Actualización:</span> {new Date(templates.find(t=>t.id===selectedId)?.updatedAt || 0).toLocaleString()}</div>
                <div className="station-tech-item"><span className="station-tech-label">Engine:</span> HANDLEBARS v4</div>
