'use client';

import React, { useState, useMemo } from 'react';
import { useLog } from '@/lib/context/LogContext';
import { useLanguage } from '@/lib/context/LanguageContext';
import { 
  XIcon, 
  CopyIcon, 
  ArrowUpIcon, 
  ArrowDownIcon, 
  FilterIcon, 
  SearchIcon,
  TerminalIcon 
} from '@/components/common/Icons';

export const LogDrawer: React.FC = () => {
  const { logs, isOpen, setIsOpen, isMaximized, setIsMaximized, clearLogs, addLog } = useLog();
  const { t } = useLanguage();
  const [search, setSearch] = useState('');
  const [appFilter, setAppFilter] = useState('');

  const filteredLogs = useMemo(() => {
    return logs.filter(log => {
      const matchesSearch = log.message.toLowerCase().includes(search.toLowerCase()) ||
                           log.app.toLowerCase().includes(search.toLowerCase()) ||
                           log.timestamp.includes(search.toLowerCase());
      const matchesApp = !appFilter || log.app === appFilter;
      return matchesSearch && matchesApp;
    });
  }, [logs, search, appFilter]);

  const uniqueApps = useMemo(() => {
    const apps = new Set(logs.map(l => l.app));
    return Array.from(apps);
  }, [logs]);

  const handleCopy = () => {
    const text = filteredLogs.map(l => `[${l.timestamp}] [${l.app}] [${l.level.toUpperCase()}] ${l.message}`).join('\n');
    navigator.clipboard.writeText(text);
    // Notificación silenciosa en el stream de logs
    addLog('SHELL', t('logs.copied').toUpperCase(), 'success');
  };

  return (
    <div 
      className={`log-drawer station-terminal station-console-anim-container ${isOpen ? 'open' : ''}`}
      style={{
        position: 'fixed',
        bottom: '32px',
        left: '250px',
        right: '0',
        height: isMaximized ? '60vh' : '250px',
        background: 'var(--surface-color)',
        borderTop: '4px solid var(--border-color)',
        zIndex: 2000,
        display: 'flex',
        flexDirection: 'column',
        boxShadow: '0 -10px 30px rgba(0, 0, 0, 0.5)',
        borderLeft: '1px solid var(--border-color)',
        transform: isOpen ? 'translateY(0)' : 'translateY(100%)',
        opacity: isOpen ? 1 : 0,
        pointerEvents: isOpen ? 'auto' : 'none',
      }}
    >
      {/* Toolbar */}
      <header className="station-console-header" style={{ padding: '8px 16px', background: 'rgba(0,0,0,0.1)' }}>
        {/* Left: Filters */}
        <div className="flex-row" style={{ alignItems: 'center', gap: '16px', flex: 1 }}>
          <div className="station-registry-sync-actions" style={{ gap: '8px' }}>
            <div style={{ position: 'relative', display: 'flex', alignItems: 'center' }}>
              <SearchIcon size={14} style={{ position: 'absolute', left: '12px', opacity: 0.5 }} />
              <input 
                type="text" 
                className="station-input"
                placeholder={t('logs.filter_placeholder').toUpperCase()} 
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                style={{
                  paddingLeft: '32px',
                  fontSize: '0.7rem',
                  width: '200px',
                  height: '32px'
                }}
              />
            </div>

            <select 
              className="station-select"
              value={appFilter}
              onChange={(e) => setAppFilter(e.target.value)}
              style={{
                fontSize: '0.7rem',
                height: '32px',
                padding: '0 12px'
              }}
            >
              <option value="">{t('logs.all_apps').toUpperCase()}</option>
              {uniqueApps.map(app => <option key={app} value={app}>{app.toUpperCase()}</option>)}
            </select>
          </div>

          <button 
            className="station-btn"
            onClick={clearLogs}
            style={{ 
              color: 'var(--status-err)', 
              fontSize: '0.65rem',
              fontWeight: 900,
              padding: '4px 12px',
              border: 'none',
              background: 'rgba(239, 68, 68, 0.1)'
            }}
          >
            {t('logs.clear_console').toUpperCase()}
          </button>
        </div>

        {/* Right: Controls */}
        <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
          <button onClick={handleCopy} title={t('logs.copied')} className="station-icon-btn">
            <CopyIcon size={16} />
          </button>
          <button onClick={() => setIsMaximized(!isMaximized)} className="station-icon-btn">
            {isMaximized ? <ArrowDownIcon size={18} /> : <ArrowUpIcon size={18} />}
          </button>
          <button onClick={() => setIsOpen(false)} className="station-icon-btn">
            <XIcon size={18} />
          </button>
        </div>
      </header>

      {/* Log Entries */}
      <div className="station-shell-content" style={{ flex: 1, overflowY: 'auto', padding: '16px', fontFamily: 'var(--font-mono)', fontSize: '0.8rem', background: 'rgba(0,0,0,0.05)' }}>
        {filteredLogs.map((log) => (
          <div key={log.id} className="log-entry" style={{ 
            display: 'flex', 
            gap: '16px', 
            marginBottom: '6px',
            color: log.level === 'error' ? 'var(--status-err)' : 
                   log.level === 'warn' ? 'var(--status-warn)' : 
                   log.level === 'success' ? 'var(--status-ok)' : 'var(--text-primary)',
            padding: '4px 0',
            borderBottom: '1px solid rgba(255,255,255,0.03)'
          }}>
            <span className="log-time" style={{ opacity: 0.4, whiteSpace: 'nowrap', fontSize: '0.7rem' }}>[{log.timestamp.split('T')[1].split('.')[0]}]</span>
            <span className="log-app" style={{ 
              fontWeight: 900, 
              minWidth: '70px', 
              color: 'var(--primary-color)',
              fontSize: '0.7rem',
              letterSpacing: '0.05rem'
            }}>{log.app.toUpperCase()}</span>
            <span className="log-msg" style={{ flex: 1, wordBreak: 'break-all', opacity: 0.9 }}>{log.message}</span>
          </div>
        ))}
        {filteredLogs.length === 0 && (
          <div className="station-empty-state" style={{ minHeight: '100px' }}>
             <span className="station-shimmer-text">{t('logs.empty_stream').toUpperCase()}</span>
          </div>
        )}
      </div>
    </div>
  );
};

/**
 * Industrial Security & Sync Dialog (Phase 9)
 * Console for managing MFA and P2P synchronization settings.
 */
'use client';

import React, { useState, useEffect } from 'react';
import { useWorkspace } from '@/lib/context/WorkspaceContext';
import { generateTotpSecret, buildOtpAuthUri } from '@/lib/utils/mfa.utils';
import { QrGenerator } from '@/lib/utils/qr.utils';
import { coreDb } from '@/lib/db/SystemDB';
import { SyncPanel } from './SyncPanel';
import { LockIcon, ShieldCheckIcon, RefreshIcon, XIcon, CheckIcon, KeyIcon } from '../common/Icons';

interface SecurityDialogProps {
  isOpen: boolean;
  onClose: () => void;
}

export const SecurityDialog: React.FC<SecurityDialogProps> = ({ isOpen, onClose }) => {
  const { currentOperator } = useWorkspace();
  const [activeTab, setActiveTab] = useState<'MFA' | 'SYNC'>('MFA');
  const [mfaEnabled, setMfaEnabled] = useState(currentOperator?.mfaEnabled || false);
  const [mfaSecret, setMfaSecret] = useState(currentOperator?.mfaSecret || '');
  const [qrSvg, setQrSvg] = useState<string | null>(null);
  const [isSaving, setIsSaving] = useState(false);

  useEffect(() => {
    if (isOpen && currentOperator) {
      setMfaEnabled(!!currentOperator.mfaEnabled);
      setMfaSecret(currentOperator.mfaSecret || '');
    }
  }, [isOpen, currentOperator]);

  const handleGenerateMfa = () => {
    const secret = generateTotpSecret();
    const uri = buildOtpAuthUri(secret, currentOperator?.displayName || 'Operator');
    const svg = QrGenerator.generateSvg(uri, 200);
    setMfaSecret(secret);
    setQrSvg(svg);
  };

  const handleSaveMfa = async () => {
    if (!currentOperator) return;
    setIsSaving(true);
    try {
      await coreDb.operators.update(currentOperator.id, {
        mfaEnabled: mfaEnabled,
        mfaSecret: mfaSecret,
        updatedAt: Date.now()
      });
      // In a real app, we'd refresh the currentOperator in context
      window.location.reload(); 
    } catch (err) {
      console.error(err);
    } finally {
      setIsSaving(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="station-modal-overlay">
       <div className="station-modal" style={{ width: '800px', maxWidth: '95vw' }}>
          <header className="station-modal-header technical-header-small">
             <div className="flex-row" style={{ gap: '12px', alignItems: 'center' }}>
                <LockIcon size={20} color="var(--primary-color)" />
                <h2 style={{ fontSize: '0.75rem', letterSpacing: '2px', fontWeight: 900, opacity: 0.5, margin: 0 }}>SECURITY & INTEROP CONSOLE</h2>
             </div>
             <button onClick={onClose} className="station-btn secondary tiny">
                <XIcon size={18} />
             </button>
          </header>

          <div className="station-modal-content" style={{ padding: 0, display: 'grid', gridTemplateColumns: '220px 1fr', height: '500px', overflow: 'hidden' }}>
             {/* Sidebar Tabs */}
             <div style={{ background: 'var(--surface-color)', borderRight: '1px solid var(--border-color)', padding: '16px', display: 'flex', flexDirection: 'column', gap: '8px' }}>
                <button 
                  className={`station-nav-item ${activeTab === 'MFA' ? 'active' : ''}`}
                  onClick={() => setActiveTab('MFA')}
                  style={{ border: 'none', background: 'transparent' }}
                >
                  <ShieldCheckIcon size={18} />
                  <span style={{ fontSize: '0.7rem', fontWeight: 800 }}>DOBLE FACTOR</span>
                </button>
                <button 
                  className={`station-nav-item ${activeTab === 'SYNC' ? 'active' : ''}`}
                  onClick={() => setActiveTab('SYNC')}
                  style={{ border: 'none', background: 'transparent' }}
                >
                  <RefreshIcon size={18} />
                  <span style={{ fontSize: '0.7rem', fontWeight: 800 }}>P2P SYNC</span>
                </button>
             </div>

             {/* Content Area */}
             <div className="flex-col" style={{ padding: '32px', overflowY: 'auto' }}>
                {activeTab === 'MFA' && (
                  <div className="flex-col" style={{ gap: '32px', height: '100%' }}>
                     <div>
                        <h3 className="section-title-technical" style={{ color: 'var(--primary-color)', marginBottom: '16px' }}>CONFIGURACIÓN TOTP</h3>
                        <div className="flex-row" style={{ gap: '12px', alignItems: 'center', background: 'var(--surface-color)', padding: '20px', border: '1px solid var(--border-color)', borderRadius: '2px' }}>
                           <input 
                            type="checkbox" 
                            checked={mfaEnabled} 
                            onChange={(e) => setMfaEnabled(e.target.checked)}
                            style={{ width: '20px', height: '20px', cursor: 'pointer' }}
                           />
                           <label style={{ fontSize: '0.75rem', fontWeight: 800, fontFamily: 'var(--font-mono)' }}>HABILITAR SEGUNDO FACTOR (APP)</label>
                        </div>
                     </div>

                     {mfaEnabled && (
                       <div className="flex-col animate-fade-in" style={{ gap: '24px' }}>
                          <p style={{ fontSize: '0.7rem', opacity: 0.5, lineHeight: '1.6', fontFamily: 'var(--font-mono)' }}>
                            Escanee el código QR con Google Authenticator o Microsoft Authenticator para vincular su terminal de forma segura.
                          </p>

                          {mfaSecret && (
                            <div className="flex-col" style={{ alignItems: 'center', gap: '20px', background: '#fff', padding: '32px', borderRadius: '4px', border: '4px solid var(--primary-color)' }}>
                               <div dangerouslySetInnerHTML={{ __html: qrSvg || '' }} />
                               <div className="flex-col" style={{ alignItems: 'center' }}>
                                  <span style={{ color: '#000', fontSize: '0.6rem', opacity: 0.5, fontWeight: '900', letterSpacing: '1px' }}>CÓDIGO_SECRETO_INDUSTRIAL</span>
                                  <code style={{ fontSize: '1.4rem', color: '#000', fontWeight: 900, letterSpacing: '4px' }}>{mfaSecret}</code>
                               </div>
                            </div>
                          )}

                          <button className="station-btn secondary" onClick={handleGenerateMfa} style={{ height: '40px' }}>
                             <KeyIcon size={16} />
