'use client';

import { useEffect, useRef, useState, useCallback } from 'react';
import type {
  AuditWorkerInMessage,
  AuditWorkerOutMessage,
  GawebSummary,
  GawebRow,
  GawebErrorLite,
} from '../types/audit-worker.types';
import { PackageAuditResult } from '../logic/package-auditor.logic';

export interface AuditProgress {
  processedLines: number;
  errorsSoFar: number;
  warningsSoFar: number;
}

export interface UseAuditWorkerResult {
  isRunning: boolean;
  progress: AuditProgress | null;
  summary: GawebSummary | null;
  packageResult: PackageAuditResult | null;
  dataWindows: Map<string, GawebRow[]>;
  errorsWindows: Map<string, GawebErrorLite[]>;

  startAudit: (args: { gawebFile: File; zipFile?: File; md5Witness?: string }) => void;
  requestDataWindow: (start: number, end: number) => void;
  requestErrorsWindow: (start: number, end: number) => void;
  cancelAudit: () => void;
  reset: () => void;
}

export function useAuditWorker(options: { maxErrorsPreview?: number; encoding?: string } = {}): UseAuditWorkerResult {
  const workerRef = useRef<Worker | null>(null);

  const [isRunning, setIsRunning] = useState(false);
  const [progress, setProgress] = useState<AuditProgress | null>(null);
  const [summary, setSummary] = useState<GawebSummary | null>(null);
  const [packageResult, setPackageResult] = useState<PackageAuditResult | null>(null);

  const [dataWindows, setDataWindows] = useState<Map<string, GawebRow[]>>(new Map());
  const [errorsWindows, setErrorsWindows] = useState<Map<string, GawebErrorLite[]>>(new Map());

  useEffect(() => {
    if (typeof window === 'undefined') return;

    // Industrial URL pattern para workers en Next.js
    const worker = new Worker(new URL('../workers/gaweb-audit.worker.ts', import.meta.url));
    workerRef.current = worker;

    worker.onmessage = (event: MessageEvent<AuditWorkerOutMessage>) => {
      const msg = event.data;

      switch (msg.type) {
        case 'PROGRESS':
          setProgress(msg.payload);
          break;
        case 'SUMMARY_READY':
          setSummary(msg.payload);
          break;
        case 'DATA_WINDOW':
          setDataWindows(prev => {
            const next = new Map(prev);
            next.set(`${msg.payload.start}-${msg.payload.end}`, msg.payload.rows);
            return next;
          });
          break;
        case 'ERRORS_WINDOW':
          setErrorsWindows(prev => {
            const next = new Map(prev);
            next.set(`${msg.payload.start}-${msg.payload.end}`, msg.payload.errors);
            return next;
          });
          break;
        case 'PACKAGE_RESULT':
          setPackageResult(msg.payload);
          break;
        case 'COMPLETE':
          setIsRunning(false);
          break;
        case 'FATAL_ERROR':
          setIsRunning(false);
          console.error('Audit Worker Fatal Error:', msg.payload.message);
          break;
      }
    };

    return () => {
      worker.terminate();
      workerRef.current = null;
    };
  }, []);

  const reset = useCallback(() => {
    setIsRunning(false);
    setProgress(null);
    setSummary(null);
    setPackageResult(null);
    setDataWindows(new Map());
    setErrorsWindows(new Map());
  }, []);

  const startAudit = useCallback(({ gawebFile, zipFile, md5Witness }: { gawebFile: File; zipFile?: File; md5Witness?: string }) => {
    if (!workerRef.current) return;
    reset();
    setIsRunning(true);

    workerRef.current.postMessage({
      type: 'START_AUDIT',
      payload: {
        gawebFile,
        zipFile,
        md5Witness,
        encoding: options.encoding || 'iso-8859-1',
        maxErrorsPreview: options.maxErrorsPreview || 1000
      }
    });
  }, [reset, options.encoding, options.maxErrorsPreview]);

  const requestDataWindow = useCallback((start: number, end: number) => {
    const key = `${start}-${end}`;
    if (dataWindows.has(key) || !workerRef.current) return;
    workerRef.current.postMessage({ type: 'REQUEST_DATA_WINDOW', payload: { start, end } });
  }, [dataWindows]);

  const requestErrorsWindow = useCallback((start: number, end: number) => {
    const key = `${start}-${end}`;
    if (errorsWindows.has(key) || !workerRef.current) return;
    workerRef.current.postMessage({ type: 'REQUEST_ERRORS_WINDOW', payload: { start, end } });
  }, [errorsWindows]);

  const cancelAudit = useCallback(() => {
    if (workerRef.current) workerRef.current.postMessage({ type: 'CANCEL_AUDIT' });
    setIsRunning(false);
  }, []);

  return {
    isRunning,
    progress,
    summary,
    packageResult,
    dataWindows,
    errorsWindows,
    startAudit,
    requestDataWindow,
    requestErrorsWindow,
    cancelAudit,
    reset
  };
}

import { useState, useCallback } from 'react';
import { CryptoService } from '@/lib/services/crypto.service';
import { useLanguage } from '@/lib/context/LanguageContext';
import { useLog } from '@/lib/context/LogContext';
import { sanitizeFileName } from '@/lib/utils/path';
import { LogLevel } from '../types/log.types';

export interface LogEntry {
  id: string;
  timestamp: Date;
  type: 'info' | 'success' | 'error' | 'skip';
  message: string;
  fileName?: string;
}

interface UseFileBatchProcessorProps {
  password?: string;
  outputSuffix?: string;
}

/**
 * Hook to manage the complex batch processing of files (Encryption/Decryption).
 */
export const useFileBatchProcessor = ({
  password,
  outputSuffix = '_decrypted'
}: UseFileBatchProcessorProps) => {
  const { t } = useLanguage();
  const { addLog: globalAddLog, clearLogs: globalClearLogs } = useLog();
  const [isProcessing, setIsProcessing] = useState(false);
  const [stats, setStats] = useState({ success: 0, error: 0, skip: 0 });

  const addLog = useCallback((type: LogEntry['type'], messageKey: string, fileName?: string, params?: any) => {
    // Map internal types to global levels
    let level: LogLevel = 'info';
    if (type === 'success') level = 'success';
    if (type === 'error') level = 'error';
    if (type === 'skip') level = 'warn';

    globalAddLog('CRYPT', t(messageKey, params), level, { fileName });
  }, [t, globalAddLog]);

  const clearLogs = useCallback(() => {
    globalClearLogs();
    setStats({ success: 0, error: 0, skip: 0 });
  }, [globalClearLogs]);

  const processFiles = useCallback(async (files: File[], mode: 'encrypt' | 'decrypt') => {
    if (!password) {
      addLog('error', 'logs.pwd_required');
      return;
    }

    setIsProcessing(true);
    setStats({ success: 0, error: 0, skip: 0 });
    addLog('info', mode === 'encrypt' ? 'logs.start_enc' : 'logs.start_dec');

    let sCount = 0;
    let eCount = 0;
    let kCount = 0;

    for (const file of files) {
      try {
        // Validation logic
        if (mode === 'encrypt' && file.name.endsWith('.enc')) {
          addLog('skip', 'logs.skip_enc', file.name);
          kCount++;
          setStats(prev => ({ ...prev, skip: kCount }));
          continue;
        }

        if (mode === 'decrypt' && !file.name.endsWith('.enc')) {
          addLog('skip', 'logs.skip_dec', file.name);
          kCount++;
          setStats(prev => ({ ...prev, skip: kCount }));
          continue;
        }

        let resultBlob: Blob;
        let finalName: string;

        if (mode === 'encrypt') {
          resultBlob = await CryptoService.encryptFile(file, password);
          const safeSuffix = sanitizeFileName(outputSuffix);
          finalName = `${file.name}${safeSuffix}`;
        } else {
          resultBlob = await CryptoService.decryptFile(file, password);
          const baseName = file.name.replace(/\.enc$/, '');
          const safeSuffix = sanitizeFileName(outputSuffix);
          finalName = `${baseName}${safeSuffix}`;
        }

        // Trigger Download
        const url = URL.createObjectURL(resultBlob);
        const a = document.createElement('a');
        a.href = url;
        a.download = finalName;
        a.click();
        URL.revokeObjectURL(url);

        addLog('success', 'logs.success', file.name);
        sCount++;
        setStats(prev => ({ ...prev, success: sCount }));
      } catch (error: any) {
        addLog('error', error.message || 'logs.error', file.name);
        eCount++;
        setStats(prev => ({ ...prev, error: eCount }));
      }
    }

    addLog('info', 'logs.summary', undefined, { s: sCount, e: eCount, k: kCount });

    // REGISTRO DE AUDITORÍA: BATCH CRYPT COMPLETADO
    try {
      const { db } = await import('@/lib/db/db');
      await db.audit_history_v6.add({
        id: crypto.randomUUID(),
        timestamp: Date.now(),
        module: 'CRYPT',
        action: 'CRYPT_BATCH_COMPLETED',
        status: eCount > 0 ? 'WARNING' : 'SUCCESS',
        details: JSON.stringify({
          mode: mode.toUpperCase(),
          total: files.length,
          success: sCount,
          errors: eCount,
          skipped: kCount
        })
      } as any);
    } catch (e) {
      console.error('Failed to log crypt audit', e);
    }

    setIsProcessing(false);
  }, [password, outputSuffix, t, addLog]);

  return {
    stats,
    isProcessing,
    processFiles,
    clearLogs,
    addLog
  };
};

import { useEffect, useCallback } from 'react';

interface UseInactivityPurgeProps {
  password: string;
  onPurge: (message: string) => void;
  timeoutMs?: number;
}

/**
 * Hook to automatically purge the master password after a period of inactivity.
 */
export const useInactivityPurge = ({
  password,
  onPurge,
  timeoutMs = 5 * 60 * 1000 // Default 5 minutes
}: UseInactivityPurgeProps) => {

  const resetTimer = useCallback(() => {
    // This function can be exposed if needed to manually reset
  }, []);

  useEffect(() => {
    if (!password) return;

    let timer: NodeJS.Timeout;

    const handleInactivity = () => {
      if (timer) clearTimeout(timer);
      timer = setTimeout(() => {
        onPurge('session_expired');
      }, timeoutMs);
    };

    // Events that reset the timer
    const activityEvents = ['mousemove', 'keydown', 'mousedown', 'touchstart'];

    const resetAndHandle = () => {
      handleInactivity();
    };

    activityEvents.forEach(event => {
      window.addEventListener(event, resetAndHandle);
    });

    // Initial trigger
    handleInactivity();

    return () => {
      if (timer) clearTimeout(timer);
      activityEvents.forEach(event => {
        window.removeEventListener(event, resetAndHandle);
      });
    };
  }, [password, onPurge, timeoutMs]);

  return { resetTimer };
};

'use client';
import { useEffect, useState } from 'react';

/**
 * Industrial Hook for detecting narrow viewports (Phase 15).
 * Useful for switching between dense table views and master-detail mobile layouts.
 */
export function useIsNarrowLayout(maxWidth = 900) {
  const [isNarrow, setIsNarrow] = useState(false);

  useEffect(() => {
    if (typeof window === 'undefined') return;

    const mq = window.matchMedia(`(max-width: ${maxWidth}px)`);

    const update = () => setIsNarrow(mq.matches);

    // Initial check
    update();

    mq.addEventListener('change', update);
    return () => mq.removeEventListener('change', update);
  }, [maxWidth]);

  return isNarrow;
}

import { useState, useCallback } from 'react';
import { useLanguage } from '@/lib/context/LanguageContext';

export interface LogEntry {
  id: string;
  timestamp: Date;
  type: 'info' | 'success' | 'error' | 'skip';
  message: string;
  fileName?: string;
}

/**
 * Common hook for modules that use the LogConsole.
 */
export const useLogs = () => {
  const { t } = useLanguage();
  const [logs, setLogs] = useState<LogEntry[]>([]);

  const addLog = useCallback((type: LogEntry['type'], messageKey: string, fileName?: string, params?: any) => {
    const newLog: LogEntry = {
      id: Math.random().toString(36).substring(2, 11),
      timestamp: new Date(),
      type,
      message: t(messageKey, params),
      fileName
    };
    setLogs(prev => [...prev, newLog]);
  }, [t]);

  const clearLogs = useCallback(() => setLogs([]), []);

  const saveLogs = useCallback((moduleName: string = 'abdfn') => {
    if (logs.length === 0) return;

    const logText = logs
      .map(l => `[${l.timestamp.toISOString()}] [${l.type.toUpperCase()}] ${l.fileName ? l.fileName + ': ' : ''}${l.message}`)
      .join('\n');

    const blob = new Blob([logText], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `log_${moduleName.toLowerCase()}_${new Date().toISOString().split('T')[0]}.txt`;
    a.click();
    URL.revokeObjectURL(url);

    addLog('success', 'logs.logs_exported');
  }, [logs, addLog]);

  return {
    logs,
    addLog,
    clearLogs,
    saveLogs
  };
};

