/**
 * generateCanvasFingerprint (Normalized v2)
 * Procesa un canvas de renderizado para obtener su huella SHA-256 industrial.
 */
export async function generateCanvasFingerprint(
  canvas: HTMLCanvasElement,
  targetWidth: number = 512,
  targetHeight: number = 724
): Promise<string> {
  const tmp = document.createElement('canvas');
  tmp.width = targetWidth;
  tmp.height = targetHeight;

  const tctx = tmp.getContext('2d', { willReadFrequently: true })!;
  tctx.drawImage(canvas, 0, 0, targetWidth, targetHeight);

  const imgData = tctx.getImageData(0, 0, targetWidth, targetHeight);
  const grayBytes = new Uint8Array(targetWidth * targetHeight);

  for (let i = 0, j = 0; i < imgData.data.length; i += 4, j++) {
    const r = imgData.data[i];
    const g = imgData.data[i + 1];
    const b = imgData.data[i + 2];
    // Luminancia industrial (BT.601)
    grayBytes[j] = (r * 0.299 + g * 0.587 + b * 0.114) | 0;
  }

  const digest = await crypto.subtle.digest('SHA-256', grayBytes);
  return Array.from(new Uint8Array(digest))
    .map((b) => b.toString(16).padStart(2, '0'))
    .join('');
}

export async function verifyGoldenLayout(
  currentCanvas: HTMLCanvasElement, 
  goldenHash: string
): Promise<boolean> {
  const currentHash = await generateCanvasFingerprint(currentCanvas);
  return currentHash === goldenHash;
}

/**
 * Package Auditor Logic
 * Compliance: 02-code-quality-architecture (English logic)
 * Compliance: 04-compliance-security (Zero-Knowledge, Safe ZIP handling)
 * 
 * This module cross-references a GAWEB index with a ZIP archive.
 */

import JSZip from 'jszip';
import { GawebAuditResult } from './gaweb-auditor.logic';
import { md5 } from '../utils/crypto.utils';

export interface PackageAuditResult {
  zipFilesCount: number;
  missingFiles: string[];
  orphanedFiles: string[];
  md5Match?: boolean;
}

/**
 * Cross-references GAWEB records with ZIP archive entries.
 */
export async function auditPackageIntegrity(
  gaweb: GawebAuditResult, 
  zipBlob: Blob,
  md5Witness?: string
): Promise<PackageAuditResult> {
  const zip = new JSZip();
  const content = await zip.loadAsync(zipBlob);
  const zipFileNames = Object.keys(content.files);
  const normalizedZipNames = new Set(zipFileNames.map(n => n.toLowerCase()));

  const result: PackageAuditResult = {
    zipFilesCount: zipFileNames.length,
    missingFiles: [],
    orphanedFiles: [],
  };

  // 1. MD5 Witness Check (Optional)
  if (md5Witness) {
     const buffer = await zipBlob.arrayBuffer();
     const textContent = new TextDecoder().decode(new Uint8Array(buffer));
     const calculatedMd5 = md5(textContent); // Simplified for browser blobs
     result.md5Match = (calculatedMd5.toLowerCase() === md5Witness.trim().toLowerCase());
  }

  // 2. Cross-Integrity Check
  // Each record in GAWEB must have a corresponding PDF in the ZIP
  const gawebReferencedFiles = new Set<string>();

  gaweb.parsedData.forEach((record, index) => {
    const rawPdfName = record['PdfName'] || '';
    const cleanPdfName = rawPdfName.trim();

    if (cleanPdfName) {
      const targetFile = `${cleanPdfName}.pdf`.toLowerCase();
      gawebReferencedFiles.add(targetFile);

      if (!normalizedZipNames.has(targetFile)) {
        // Add to gaweb errors as well for UI visibility
        gaweb.errors.push({
          line: index + 1,
          field: 'PdfName',
          position: '212-251', // Modern position for PdfName
          severity: 'ERROR',
          messageKey: 'audit.errors.missing_pdf',
          value: cleanPdfName
        });
        result.missingFiles.push(cleanPdfName);
      }
    }
  });

  // 3. Orphan Check (Optional Warnings)
  // Check if there are PDFs in the ZIP that are not in the index
  zipFileNames.forEach(zipFile => {
    if (zipFile.toLowerCase().endsWith('.pdf') && !gawebReferencedFiles.has(zipFile.toLowerCase())) {
      result.orphanedFiles.push(zipFile);
      // Add a warning to the overall audit
      gaweb.warnings.push({
        line: 0,
        field: 'ZIP',
        position: 'N/A',
        severity: 'WARNING',
        messageKey: 'audit.errors.orphaned_pdf',
        value: zipFile
      });
    }
  });

  return result;
}

import { coreDb } from '../db/SystemDB';
import { db } from '../db/db';
import { AuditRecord, AuditDetails } from '../types/auth.types';
import { resolveAuditCategory } from '../types/audit.types';

/**
 * Unified Audit Service (Phase 11.2)
 * Orchestrates logging between Global (Core) and Operational (Unit) registries.
 */
class AuditService {
  /**
   * Main logging method.
   * Redirects to Core for SECURITY/SYSTEM/SUPERVISOR events, or Unit for others.
   */
  async log(record: Omit<AuditRecord, 'id' | 'timestamp'>) {
    const entry: AuditRecord = {
      ...record,
      id: crypto.randomUUID(),
      timestamp: Date.now()
    };

    try {
      const detailsJson = JSON.stringify(entry.details || {});
      const category = resolveAuditCategory(entry.messageKey);

      if (entry.module === 'SECURITY' || entry.module === 'SYSTEM' || entry.module === 'SUPERVISOR') {
        // Global Audit (CoreDB)
        await coreDb.system_log.add({
          id: entry.id!,
          timestamp: entry.timestamp,
          category,
          action: entry.messageKey,
          status: entry.status,
          details: detailsJson
        });
        console.log(`[AUDIT-CORE] ${entry.module} [${category}] - ${entry.messageKey}`, entry.details);
      } else {
        // Operational Audit (UnitDB)
        if (db && (db as any).audit_history_v6) {
          await db.audit_history_v6.add({
            id: entry.id!,
            timestamp: entry.timestamp,
            category,
            module: entry.module as any,
            action: entry.messageKey,
            status: entry.status as any,
            details: detailsJson
          });
          console.log(`[AUDIT-UNIT] ${entry.module} [${category}] - ${entry.messageKey}`, entry.details);
        } else {
          console.warn('[AUDIT-SERVICE] Unit DB not available for logging operational event:', entry);
        }
      }
    } catch (err) {
      console.error('[AUDIT-SERVICE] Failed to log event', err, entry);
    }
  }

  /**
   * Helper for security events
   */
  async logSecurity(messageKey: string, details: AuditDetails, operatorId?: string) {
    await this.log({
      module: 'SECURITY',
      messageKey,
      details,
      status: details.severity === 'CRITICAL' ? 'WARNING' : 'INFO',
      operatorId
    });
  }
}

