/**
 * Compliance Report Service (Phase 10)
 * Generates audit master reports in industrial formats (CSV/PDF).
 */
import { GlobalTelemetrySnapshot, TelemetryConfig } from '../types/telemetry.types';
import { TelemetryConfigService } from './telemetry-config.service';

export class ComplianceReportService {
  /**
   * Generates a Master Audit CSV report containing all unit KPIs.
   */
  static async generateGlobalCsv(snapshot: GlobalTelemetrySnapshot): Promise<Blob> {
    const config = await TelemetryConfigService.loadConfig();
    const rows: string[] = [];

    // Header Industrial
    rows.push(`ABDFN SUITE - MASTER AUDIT REPORT`);
    rows.push(`PLANT:;${config.corporate.plantName}`);
    rows.push(`DATE:;${new Date(snapshot.generatedAt).toISOString()}`);
    rows.push(`SUITE_VERSION:;${snapshot.suiteVersion}`);
    rows.push(``);

    // Global Totals
    rows.push(`GLOBAL METRICS (LAST 24H)`);
    rows.push(`Total Units:;${snapshot.globalTotals.totalUnits}`);
    rows.push(`Total Docs:;${snapshot.globalTotals.totalDocs24h}`);
    rows.push(`Total Audits:;${snapshot.globalTotals.totalAudits24h}`);
    rows.push(`Total QA Breaks:;${snapshot.globalTotals.totalQaBreaks24h}`);
    rows.push(``);

    // Unit Detail
    rows.push(`UNIT DETAIL`);
    rows.push(`UNIT_CODE;HEALTH;LAST_ACTIVITY;DOCS_24H;AUDITS_24H;QA_MATCH;QA_BREAK;QA_NOGOLDEN;SEC_FAIL;SEC_LOCK;SEC_TECH`);

    for (const u of snapshot.units) {
      const b24 = u.kpiBuckets.find(b => b.bucket === 'LAST_24H')!;
      const row = [
        u.unitCode,
        u.health,
        u.lastActivityAt ? new Date(u.lastActivityAt).toISOString() : '---',
        b24.docsProcessed,
        b24.auditsRun,
        b24.letterQaLotes.match,
        b24.letterQaLotes.break,
        b24.letterQaLotes.noGolden,
        u.security.failedLogins,
        u.security.locksTriggered,
        u.security.techModeActivations
      ];
      rows.push(row.join(';'));
    }

    const content = rows.join('\n');
    return new Blob([content], { type: 'text/csv;charset=utf-8;' });
  }

  /**
   * Triggers the download of the CSV report.
   */
  static downloadBlob(blob: Blob, filename: string): void {
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    a.click();
    setTimeout(() => URL.revokeObjectURL(url), 100);
  }
}

/**
 * CryptoService - Web Crypto Implementation of the ABDFN Encryption Standard.
 * 
 * Replicates the logic of ABDTools.Core.Crypto.CryptoService to ensure 
 * 100% compatibility with files encrypted via the original C# utility.
 */

const SALT_SIZE = 16;      // 128-bit
const NONCE_SIZE = 12;     // 96-bit (GCM standard)
const KEY_SIZE = 32;       // AES-256
const TAG_SIZE = 16;       // 128-bit (GCM standard)
const ITERATIONS = 100000; // PBKDF2 iterations (matching C#)

import { EncryptedFieldContainer, AADPayload } from '../types/crypto.types';

export interface ProcessingResult {
  success: boolean;
  fileName: string;
  error?: string;
  skipped?: boolean;
}

export class CryptoService {
  /**
   * Derives a 256-bit key from a password and salt using PBKDF2.
   */
  private static async deriveKey(password: string, salt: Uint8Array): Promise<CryptoKey> {
    const encoder = new TextEncoder();
    const passwordBytes = encoder.encode(password);

    // Import the raw password as a key for PBKDF2
    const baseKey = await crypto.subtle.importKey(
      'raw',
      passwordBytes.buffer as ArrayBuffer,
      'PBKDF2',
      false,
      ['deriveBits', 'deriveKey']
    );

    // Derive the actual AES-GCM key
    return crypto.subtle.deriveKey(
      {
        name: 'PBKDF2',
        salt: salt.buffer as ArrayBuffer,
        iterations: ITERATIONS,
        hash: 'SHA-256'
      },
      baseKey,
      { name: 'AES-GCM', length: KEY_SIZE * 8 },
      false, // Key is not extractable
      ['encrypt', 'decrypt']
    );
  }

  /**
   * Encrypts a file using AES-256-GCM.
   * Structure: [Salt(16)] + [Nonce(12)] + [Ciphertext] + [Tag(16)] 
   * NOTE: Web Crypto appends the tag to the ciphertext.
   */
  public static async encryptFile(file: File, password: string): Promise<Blob> {
    const fileBytes = new Uint8Array(await file.arrayBuffer());

    // 1. Generate random Salt and Nonce
    const salt = crypto.getRandomValues(new Uint8Array(SALT_SIZE));
    const nonce = crypto.getRandomValues(new Uint8Array(NONCE_SIZE));

    // 2. Derive Key
    const key = await this.deriveKey(password, salt);

    // 3. Encrypt
    // For GCM, the 'tag' is automatically appended to the ciphertext by encrypt()
    const encryptedContent = await crypto.subtle.encrypt(
      {
        name: 'AES-GCM',
        iv: nonce,
        tagLength: TAG_SIZE * 8
      },
      key,
      fileBytes
    );

    // 4. Assemble: [Salt][Nonce][Ciphertext+Tag]
    // Web Crypto's encryptedContent = [Ciphertext][Tag] (16 bytes at the end)
    // Actually, C# code wrote: [Salt][Nonce][Tag][Ciphertext]
    // We MUST match the C# order exactly: [Salt][Nonce][Tag][Ciphertext]

    const encryptedArray = new Uint8Array(encryptedContent);
    const tag = encryptedArray.slice(-TAG_SIZE);
    const ciphertextOnly = encryptedArray.slice(0, -TAG_SIZE);

    const finalResult = new Uint8Array(SALT_SIZE + NONCE_SIZE + TAG_SIZE + ciphertextOnly.length);
    finalResult.set(salt, 0);
    finalResult.set(nonce, SALT_SIZE);
    finalResult.set(tag, SALT_SIZE + NONCE_SIZE);
    finalResult.set(ciphertextOnly, SALT_SIZE + NONCE_SIZE + TAG_SIZE);

    return new Blob([finalResult], { type: 'application/octet-stream' });
  }

  /**
   * Decrypts a file using AES-256-GCM.
   */
  public static async decryptFile(file: File, password: string): Promise<Blob> {
    const data = new Uint8Array(await file.arrayBuffer());

    const minSize = SALT_SIZE + NONCE_SIZE + TAG_SIZE;
    if (data.length < minSize) {
      throw new Error('Archivo demasiado corto o formato incorrecto.');
    }

    // 1. Extract components (matching C# order: Salt, Nonce, Tag, Ciphertext)
    const salt = data.slice(0, SALT_SIZE);
    const nonce = data.slice(SALT_SIZE, SALT_SIZE + NONCE_SIZE);
    const tag = data.slice(SALT_SIZE + NONCE_SIZE, SALT_SIZE + NONCE_SIZE + TAG_SIZE);
    const ciphertext = data.slice(SALT_SIZE + NONCE_SIZE + TAG_SIZE);

    // 2. Derive Key
    const key = await this.deriveKey(password, salt);

    // 3. Web Crypto expects [Ciphertext][Tag] concatenated for decryption
    const combinedData = new Uint8Array(ciphertext.length + TAG_SIZE);
    combinedData.set(ciphertext, 0);
    combinedData.set(tag, ciphertext.length);

    // 4. Decrypt
    try {
      const decryptedBuffer = await crypto.subtle.decrypt(
        {
          name: 'AES-GCM',
          iv: nonce.buffer as ArrayBuffer,
          tagLength: TAG_SIZE * 8
        },
        key,
        combinedData.buffer as ArrayBuffer
      );

      return new Blob([decryptedBuffer], { type: 'application/octet-stream' });
    } catch (e) {
      throw new Error('Contraseña incorrecta o archivo dañado.');
    }
  }

  // --- PHASE 14: AT-REST ENCRYPTION (FIELD LEVEL) ---

  /**
   * Generates a new random 256-bit Installation Key (IK).
   */
  public static async generateInstallationKey(): Promise<CryptoKey> {
    return crypto.subtle.generateKey(
      { name: 'AES-GCM', length: 256 },
      true, // Must be extractable to be wrapped/stored
      ['encrypt', 'decrypt']
    );
  }

  /**
   * Derives a Master Key from a PIN for wrapping/unwrapping the Installation Key.
   */
  public static async deriveMasterKeyFromPin(pin: string, salt: Uint8Array): Promise<CryptoKey> {
    return this.deriveKey(pin, salt);
  }

  /**
   * Encrypts a field value (string or binary) using the provided key and optional AAD.
   */
  public static async encryptField(
    value: string | ArrayBuffer | Uint8Array,
    key: CryptoKey,
    aad?: Uint8Array
  ): Promise<EncryptedFieldContainer> {
    let plainBytes: Uint8Array;
    if (typeof value === 'string') {
      plainBytes = new TextEncoder().encode(value);
    } else if (value instanceof ArrayBuffer) {
      plainBytes = new Uint8Array(value);
    } else {
      plainBytes = value;
    }

    const iv = crypto.getRandomValues(new Uint8Array(NONCE_SIZE));

    const cipherBuf = await crypto.subtle.encrypt(
      {
        name: 'AES-GCM',
        iv: iv.buffer as ArrayBuffer,
        additionalData: aad ? (aad.buffer as ArrayBuffer) : undefined,
        tagLength: TAG_SIZE * 8
      },
      key,
      plainBytes.buffer as ArrayBuffer
    );

    return {
      v: 1,
      alg: 'AES-GCM-256',
      iv: this.toBase64(iv),
      ct: this.toBase64(new Uint8Array(cipherBuf)),
      aad: aad ? this.toBase64(aad) : undefined
    };
  }

  /**
   * Decrypts a field container using the provided key and optional AAD.
   */
  public static async decryptField(
    container: EncryptedFieldContainer,
    key: CryptoKey,
    aad?: Uint8Array
  ): Promise<Uint8Array> {
    if (container.v !== 1 || container.alg !== 'AES-GCM-256') {
      throw new Error('Unsupported encrypted field format or algorithm.');
    }

    const iv = this.fromBase64(container.iv);
    const ct = this.fromBase64(container.ct);

    const plainBuf = await crypto.subtle.decrypt(
      {
        name: 'AES-GCM',
        iv: iv.buffer as ArrayBuffer,
        additionalData: aad ? (aad.buffer as ArrayBuffer) : undefined,
        tagLength: TAG_SIZE * 8
      },
      key,
      ct.buffer as ArrayBuffer
    );

    return new Uint8Array(plainBuf);
  }

  /**
   * Builds the Additional Authenticated Data (AAD) for a record field.
   */
  public static buildAAD(
    schema: 'ABDFN_CORE' | 'ABDFN_SUITE',
    unitId: string | null,
    table: string,
    id: string,
    field: string
  ): Uint8Array {
    const payload: AADPayload = { schema, unitId, table, id, field, v: 1 };
    return new TextEncoder().encode(JSON.stringify(payload));
  }

  // --- HELPERS ---

  public static toBase64(bytes: Uint8Array): string {
    return btoa(String.fromCharCode(...bytes));
  }

  public static fromBase64(b64: string): Uint8Array {
    const bin = atob(b64);
    const bytes = new Uint8Array(bin.length);
    for (let i = 0; i < bin.length; i++) {
        bytes[i] = bin.charCodeAt(i);
    }
    return bytes;
  }
}

import { db } from '../db/db';
import { SuiteDump, LetterTemplateDump } from '../types/dump.types';
import { auditService } from './AuditService';

/**
 * Industrial Utility for Full Database Export/Import (Era 6)
 * Handles binary DOCX content conversion to Base64 for JSON portability.
 * Endured with Phase 13 Security: AES-GCM Encryption + PBKDF2 Key Derivation.
 */
export class DbSyncService {

  private static SYNC_VERSION = 'abdfn-v6-crypto';
  private static ITERATIONS = 100000;

  /**
   * Generates an encrypted JSON Blob.
   */
  static async exportSuite(passphrase: string, actorId: string): Promise<Blob> {
    const [presets, templates, mappings, goldenTests, auditHistory] = await Promise.all([
      db.presets_v6.toArray(),
      db.lettertemplates_v6.toArray(),
      db.lettermappings_v6.toArray(),
      db.golden_tests_v6.toArray(),
      db.audit_history_v6.toArray(),
    ]);

    await auditService.log({
      module: 'SUPERVISOR',
      messageKey: 'sync.export.start',
      status: 'INFO',
      operatorId: actorId,
      details: {
        eventType: 'SYNC_EXPORT_START',
        entityType: 'SYNC',
        actorId,
        severity: 'INFO',
        context: { presets: presets.length, templates: templates.length }
      }
    });

    // Handle Binary Content (DOCX)
    const templatesWithBase64: LetterTemplateDump[] = await Promise.all(
      templates.map(async (tpl) => {
        const { binaryContent, ...rest } = tpl;
        const dump: LetterTemplateDump = { ...rest };
        if (binaryContent) {
          dump.binaryBase64 = this.arrayBufferToBase64(binaryContent);
        }
        return dump;
      })
    );

    const clearPayload: SuiteDump = {
      version: 'abdfn-suite-v6',
      generatedAt: new Date().toISOString(),
      presets: presets,
      templates: templatesWithBase64,
      mappings: mappings,
      goldenTests: goldenTests || [],
      auditHistory: auditHistory || [],
    };

    const encryptedContainer = await this.encrypt(JSON.stringify(clearPayload), passphrase);

    await auditService.log({
      module: 'SUPERVISOR',
      messageKey: 'sync.export.success',
      status: 'SUCCESS',
      operatorId: actorId,
      details: {
        eventType: 'SYNC_EXPORT_SUCCESS',
        entityType: 'SYNC',
        actorId,
        severity: 'INFO',
        context: { version: this.SYNC_VERSION }
      }
    });

    return new Blob([JSON.stringify(encryptedContainer, null, 2)], { type: 'application/octet-stream' });
  }

  /**
   * Imports an encrypted SuiteDump JSON into the local IndexedDB.
   */
  static async importSuite(file: File, passphrase: string, actorId: string, mode: 'REPLACE' | 'MERGE' = 'MERGE'): Promise<void> {
    const containerText = await file.text();
    const container = JSON.parse(containerText);

    if (container.version !== this.SYNC_VERSION) {
      throw new Error('VERSION_MISMATCH: Unsupported sync format');
    }

    await auditService.log({
      module: 'SUPERVISOR',
      messageKey: 'sync.import.attempt',
      status: 'INFO',
      operatorId: actorId,
      details: {
        eventType: 'SYNC_IMPORT_ATTEMPT',
        entityType: 'SYNC',
        entityId: file.name,
        actorId,
        severity: 'INFO',
        context: { mode, size: file.size }
      }
    });

    let clearJson: string;
    try {
      clearJson = await this.decrypt(container, passphrase);
    } catch (err) {
      await auditService.log({
        module: 'SECURITY',
        messageKey: 'sync.import.fail_crypto',
        status: 'ERROR',
        operatorId: actorId,
        details: {
          eventType: 'SYNC_IMPORT_FAIL',
          entityType: 'SYNC',
          severity: 'CRITICAL',
          context: { reason: 'DECRYPTION_FAILED' }
        }
      });
      throw new Error('DECRYPTION_FAILED');
    }

    const dump: SuiteDump = JSON.parse(clearJson);
    if (dump.version !== 'abdfn-suite-v6') {
      throw new Error('PAYLOAD_MISMATCH');
    }

    // Transaction for industrial integrity
    await db.transaction('readwrite', [
      db.presets_v6, 
      db.lettertemplates_v6, 
      db.lettermappings_v6, 
      db.golden_tests_v6, 
      db.audit_history_v6
    ], async () => {

      if (mode === 'REPLACE') {
        await Promise.all([
          db.presets_v6.clear(),
          db.lettertemplates_v6.clear(),
          db.lettermappings_v6.clear(),
          db.golden_tests_v6.clear(),
          db.audit_history_v6.clear(),
        ]);
      }

      const reconcile = async (table: any, incoming: { id?: string | number, updatedAt?: number }) => {
        if (mode === 'REPLACE') {
          await table.put(incoming);
          return;
        }
        const existing = await table.get(incoming.id);
        if (!existing || (incoming.updatedAt && incoming.updatedAt > (existing.updatedAt || 0))) {
          await table.put(incoming);
        }
      };

      for (const p of dump.presets) await reconcile(db.presets_v6, p);
      for (const t of dump.templates) {
        const { binaryBase64, ...rest } = t;
        const record: any = { ...rest };
        if (binaryBase64) record.binaryContent = this.base64ToArrayBuffer(binaryBase64);
        await reconcile(db.lettertemplates_v6, record);
      }
      for (const m of dump.mappings) await reconcile(db.lettermappings_v6, m);
      if (dump.goldenTests) for (const g of dump.goldenTests) await reconcile(db.golden_tests_v6, g);
      if (dump.auditHistory) for (const h of dump.auditHistory) await reconcile(db.audit_history_v6, h);
    });

    await auditService.log({
      module: 'SUPERVISOR',
      messageKey: 'sync.import.success',
      status: 'SUCCESS',
      operatorId: actorId,
      details: {
        eventType: 'SYNC_IMPORT_SUCCESS',
        entityType: 'SYNC',
        actorId,
        severity: 'INFO',
        context: { mode }
      }
    });

    console.log(`[ABDFN-SYNC] Import completed successfully. Mode: ${mode}`);
  }

  // --- CRYPTO HELPERS (WEB CRYPTO API) ---

  private static async deriveKey(passphrase: string, salt: Uint8Array): Promise<CryptoKey> {
    const enc = new TextEncoder();
    const baseKey = await crypto.subtle.importKey(
      'raw', enc.encode(passphrase), 'PBKDF2', false, ['deriveKey']
    );
    return await crypto.subtle.deriveKey(
      { name: 'PBKDF2', salt, iterations: this.ITERATIONS, hash: 'SHA-256' } as Pbkdf2Params,
      baseKey,
      { name: 'AES-GCM', length: 256 },
      false,
      ['encrypt', 'decrypt']
    );
  }

  private static async encrypt(text: string, passphrase: string) {
    const enc = new TextEncoder();
    const salt = crypto.getRandomValues(new Uint8Array(16));
    const iv = crypto.getRandomValues(new Uint8Array(12));
    const key = await this.deriveKey(passphrase, salt);

    const ciphertext = await crypto.subtle.encrypt(
      { name: 'AES-GCM', iv }, key, enc.encode(text)
    );

    return {
      version: this.SYNC_VERSION,
      kdf: 'PBKDF2-SHA256',
      iterations: this.ITERATIONS,
      salt: this.arrayBufferToBase64(salt.buffer),
      iv: this.arrayBufferToBase64(iv.buffer),
      ciphertext: this.arrayBufferToBase64(ciphertext)
    };
  }

  private static async decrypt(container: any, passphrase: string): Promise<string> {
    const dec = new TextDecoder();
    const salt = this.base64ToArrayBuffer(container.salt);
    const iv = this.base64ToArrayBuffer(container.iv);
    const ciphertext = this.base64ToArrayBuffer(container.ciphertext);
    const key = await this.deriveKey(passphrase, new Uint8Array(salt));

    const clearBuf = await crypto.subtle.decrypt(
      { name: 'AES-GCM', iv: new Uint8Array(iv) }, key, ciphertext
    );
    return dec.decode(clearBuf);
  }

  private static arrayBufferToBase64(buffer: ArrayBuffer): string {
    let binary = '';
    const bytes = new Uint8Array(buffer);
    for (let i = 0; i < bytes.byteLength; i++) {
      binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
  }

  private static base64ToArrayBuffer(base64: string): ArrayBuffer {
    const binary = atob(base64);
    const bytes = new Uint8Array(binary.length);
    for (let i = 0; i < binary.length; i++) {
      bytes[i] = binary.charCodeAt(i);
    }
    return bytes.buffer;
  }
}

import { coreDb } from '../db/SystemDB';
import { auditService } from './AuditService';
import { Operator, UserRole } from '../types/auth.types';
import { hashPin } from '../utils/crypto.utils';
import { generateTotpSecret, verifyTOTP } from '../utils/mfa.utils';

/**
 * Industrial Operator Service (Phase 11.2)
 * Handles advanced identity governance and lifecycle management.
 */
class OperatorService {
  /**
   * Helper to ensure we don't deactivate or change role of the last active ADMIN.
   */
  private async validateLastAdmin(opId: string, nextActive: number, nextRole: UserRole): Promise<boolean> {
    if (!opId) return true; // New user is safe

    const activeAdmins = await coreDb.operators
      .where('role').equals('ADMIN')
      .filter(op => op.isActive === 1)
      .toArray();

    if (activeAdmins.length === 1 && activeAdmins[0].id === opId) {
      if (nextActive === 0 || nextRole !== 'ADMIN') {
        return false;
      }
    }
    return true;
  }

  /**
   * Creates a new operator with initial PIN and audit log.
   */
  async create(data: Partial<Operator>, rawPin: string, actorId: string): Promise<string> {
    const id = crypto.randomUUID();
    const pinHash = await hashPin(rawPin);

    const newOp: Operator = {
      ...data,
      id,
      pinHash,
      createdAt: Date.now(),
      updatedAt: Date.now(),
      isActive: 1,
      isMaster: false,
      mfaEnabled: false,
    } as Operator;

    await coreDb.operators.add(newOp);

    await auditService.log({
      module: 'SECURITY',
      messageKey: 'operator.create',
      status: 'INFO',
      operatorId: actorId,
      details: {
        eventType: 'OPERATOR_CREATE',
        entityType: 'OPERATOR',
        entityId: id,
        actorId: actorId,
        severity: 'INFO',
        context: { username: newOp.username, role: newOp.role }
      }
    });

    return id;
  }

  /**
   * Updates an existing operator's profile.
   */
  async update(id: string, data: Partial<Operator>, actorId: string, newPin?: string): Promise<void> {
    const existing = await coreDb.operators.get(id);
    if (!existing) throw new Error('OPERATOR_NOT_FOUND');

    // Safety check: Last Admin
    if (data.isActive !== undefined || data.role !== undefined) {
      const isSafe = await this.validateLastAdmin(id, data.isActive ?? existing.isActive, data.role ?? existing.role);
      if (!isSafe) throw new Error('LAST_ADMIN_PROTECTION');
    }

    const updates: Partial<Operator> = {
      ...data,
      updatedAt: Date.now(),
    };

    if (newPin) {
      updates.pinHash = await hashPin(newPin);
    }

    // Advanced Audit Logic (Branch 12.1)
    const roleBefore = existing.role;
    const roleAfter = updates.role ?? existing.role;
    const roleChanged = roleBefore !== roleAfter;

    const beforeExtra = existing.extraCapabilities || [];
    const beforeDenied = existing.deniedCapabilities || [];
    const afterExtra = updates.extraCapabilities ?? beforeExtra;
    const afterDenied = updates.deniedCapabilities ?? beforeDenied;

    const overridesChanged = 
      JSON.stringify(beforeExtra) !== JSON.stringify(afterExtra) ||
      JSON.stringify(beforeDenied) !== JSON.stringify(afterDenied);

    let messageKey = 'operator.update';
    let eventType = 'OPERATOR_UPDATE';
    let severity: 'INFO' | 'WARN' | 'CRITICAL' = 'INFO';

    // Sensitivity check for critical capabilities
    const SENSITIVE_CAPS: string[] = ['SETTINGS_GLOBAL', 'OPERATORS_MANAGE', 'CRYPT_CONFIG_GLOBAL', 'AUDIT_CONFIG', 'LETTER_CONFIG_GLOBAL', 'ETL_CONFIG_GLOBAL', 'SYNC_EXPORT', 'SYNC_IMPORT'];
    const touchesSensitive = [...afterExtra, ...afterDenied, ...beforeExtra, ...beforeDenied].some(c => SENSITIVE_CAPS.includes(c));

    if (roleChanged) {
      messageKey = 'operator.role.change';
      eventType = 'OPERATOR_ROLE_CHANGE';
      severity = 'CRITICAL';
    } else if (overridesChanged) {
      messageKey = 'operator.capabilities.override';
      eventType = 'OPERATOR_CAPABILITY_OVERRIDE';
      severity = touchesSensitive ? 'CRITICAL' : 'WARN';
    }

    // PIN Unlock Detection (Phase 13)
    const wasInactive = existing.isActive === 0;
    const becomesActive = updates.isActive === 1;
    const attemptsCleared = (updates.failedPinAttempts === 0) && (existing.failedPinAttempts || 0) > 0;

    if (wasInactive && becomesActive && attemptsCleared) {
      messageKey = 'operator.pin.unlock';
      eventType = 'OPERATOR_PIN_UNLOCK';
      severity = 'INFO';
    }

    await coreDb.operators.update(id, updates);

    await auditService.log({
      module: 'SECURITY',
      messageKey,
      status: severity === 'CRITICAL' ? 'WARNING' : severity === 'WARN' ? 'WARNING' : 'INFO',
      operatorId: actorId,
      details: {
        eventType,
        entityType: 'OPERATOR',
        entityId: id,
        actorId: actorId,
        actorUser: (await coreDb.operators.get(actorId))?.username || 'system',
        severity,
        context: {
          username: existing.username,
          updates: Object.keys(data).join(', '),
          ...(roleChanged && { fromRole: roleBefore, toRole: roleAfter }),
          ...(overridesChanged && { 
            beforeExtra: beforeExtra.join(','), 
            afterExtra: afterExtra.join(','),
            beforeDenied: beforeDenied.join(','),
            afterDenied: afterDenied.join(',')
          })
        }
      }
    });
  }

  /**
   * Starts MFA Enrollment for an operator.
   */
  async startMfaEnrollment(id: string, actorId: string): Promise<{ secret: string }> {
    const existing = await coreDb.operators.get(id);
    if (!existing) throw new Error('OPERATOR_NOT_FOUND');

    const secret = generateTotpSecret();

    await coreDb.operators.update(id, {
      mfaSecret: secret,
      mfaEnabled: false, // Not enabled until confirmed
      updatedAt: Date.now()
    });

    await auditService.log({
      module: 'SECURITY',
      messageKey: 'operator.mfa.enroll_start',
      status: 'INFO',
      operatorId: actorId,
      details: {
        eventType: 'OPERATOR_MFA_ENROLL_START',
        entityType: 'OPERATOR',
        entityId: id,
        actorId,
        severity: 'INFO',
        context: { target: existing.username }
      }
    });

    return { secret };
  }

  /**
   * Confirms MFA Enrollment with a valid code.
   */
  async confirmMfaEnrollment(id: string, code: string, actorId: string): Promise<boolean> {
    const existing = await coreDb.operators.get(id);
    if (!existing || !existing.mfaSecret) throw new Error('MFA_NOT_INITIALIZED');

    const isValid = await verifyTOTP(existing.mfaSecret, code);
    if (!isValid) return false;

    await coreDb.operators.update(id, {
      mfaEnabled: true,
      failedMfaAttempts: 0,
      mfaLockedUntil: 0,
      updatedAt: Date.now()
    });

    await auditService.log({
      module: 'SECURITY',
      messageKey: 'operator.mfa.enroll_complete',
      status: 'SUCCESS',
      operatorId: actorId,
      details: {
        eventType: 'OPERATOR_MFA_ENROLL_COMPLETE',
        entityType: 'OPERATOR',
        entityId: id,
        actorId,
        severity: 'INFO',
        context: { target: existing.username }
      }
    });

    return true;
  }

  /**
   * Transfers the master (root) capability from one administrator to another.
   */
  async transferMasterRole(fromId: string, toId: string, performedById: string): Promise<void> {
    if (fromId === toId) return;

    try {
      const [from, to, actor] = await Promise.all([
        coreDb.operators.get(fromId),
        coreDb.operators.get(toId),
        coreDb.operators.get(performedById),
      ]);

      if (!from || !to || !actor) throw new Error('OPERATOR_NOT_FOUND');
      if (!from.isMaster) throw new Error('SOURCE_NOT_MASTER');
      if (from.isActive === 0 || to.isActive === 0) throw new Error('INACTIVE_OPERATOR');

      if (to.role !== 'ADMIN') {
        throw new Error('TARGET_NOT_ADMIN');
      }

      // Execute transaction for atomicity
      await coreDb.transaction('rw', [coreDb.operators, coreDb.system_log], async () => {
        await coreDb.operators.update(from.id, {
          isMaster: false,
          updatedAt: Date.now(),
        });
        await coreDb.operators.update(to.id, {
          isMaster: true,
          updatedAt: Date.now(),
        });

        // Register in security audit
        await auditService.log({
          module: 'SECURITY',
          messageKey: 'operator.master.transfer',
          status: 'WARNING',
          operatorId: actor.id,
          details: {
            eventType: 'OPERATOR_MASTER_TRANSFER',
            entityType: 'OPERATOR',
            entityId: to.id,
            actorId: actor.id,
            actorUser: actor.username,
            severity: 'CRITICAL',
            context: {
              fromId: from.id,
              fromUser: from.username,
              toId: to.id,
              toUser: to.username,
            },
          },
        });
      });

      console.log(`[OPERATOR-SERVICE] Master role successfully transferred from ${from.username} to ${to.username}`);
    } catch (err) {
      console.error('[OPERATOR-SERVICE] Master transfer failed', err);
      throw err;
    }
  }

  /**
   * Lists all operators
   */
  async list(): Promise<Operator[]> {
    return await coreDb.operators.toArray();
  }
}

