/**
 * Purges old audit records based on the user-defined retention period.
 * Maintains Industrial standards for database performance.
 */
export async function purgeOldAuditRecords() {
  const { months } = loadAuditRetention();
  const now = new Date();

  // Calculate the cutoff timestamp
  const cutoff = new Date(
    now.getFullYear(),
    now.getMonth() - (months - 1),
    1
  ).getTime();

  try {
    // Phase 8 Multi-Tenancy Guard
    if (!db.audit_history_v6) return;

    const deletedCount = await db.audit_history_v6
      .where('timestamp')
      .below(cutoff)
      .delete();

    if (deletedCount > 0) {
      console.log(`[ABDFN-RETENTION] Auto-purged ${deletedCount} legacy audit records (Retention: ${months}m).`);
    }
  } catch (e) {
    console.error('Failed to purge old audit records', e);
  }
}

export interface AuditRetentionSettings {
  months: 3 | 6 | 12 | 24;
}

const RETENTION_KEY = 'abdfn-audit-retention';

export function loadAuditRetention(): AuditRetentionSettings {
  if (typeof window === 'undefined') return { months: 12 };
  try {
    const raw = localStorage.getItem(RETENTION_KEY);
    if (!raw) return { months: 12 };
    const parsed = JSON.parse(raw) as AuditRetentionSettings;
    return parsed;
  } catch {
    return { months: 12 };
  }
}

export function saveAuditRetention(settings: AuditRetentionSettings) {
  if (typeof window === 'undefined') return;
  localStorage.setItem(RETENTION_KEY, JSON.stringify(settings));
}

/**
 * ABDFN Industrial Clsx (Vendorized)
 * A aseptic implementation of the clsx utility to ensure zero external network dependencies
 * in high-integrity industrial environments.
 */

type ClassValue = string | number | boolean | undefined | null | { [key: string]: any } | ClassValue[];

export function clsx(...inputs: ClassValue[]): string {
  let i = 0;
  let tmp: any;
  let str = '';
  const len = inputs.length;

  for (; i < len; i++) {
    if (tmp = inputs[i]) {
      if (typeof tmp === 'string') {
        str += (str && ' ') + tmp;
      } else if (Array.isArray(tmp)) {
        const x = clsx(...tmp);
        if (x) str += (str && ' ') + x;
      } else if (typeof tmp === 'object') {
        for (const k in tmp) {
          if (tmp[k]) {
            str += (str && ' ') + k;
          }
        }
      }
    }
  }

  return str;
}

export default clsx;

/**
 * Common Crypto Utilities for ABDFN Suite.
 * Implementation of industrial-strength algorithms in pure JS for zero-knowledge environments.
 */

/**
 * Calculates a standard MD5 hash (32 hex characters).
 * Optimized for performance and parity with legacy industrial witnesses.
 */
export function md5(text: string): string {
  const s = [
    7, 12, 17, 22, 7, 12, 17, 22, 7, 12, 17, 22, 7, 12, 17, 22,
    5, 9, 14, 20, 5, 9, 14, 20, 5, 9, 14, 20, 5, 9, 14, 20,
    4, 11, 16, 23, 4, 11, 16, 23, 4, 11, 16, 23, 4, 11, 16, 23,
    6, 10, 15, 21, 6, 10, 15, 21, 6, 10, 15, 21, 6, 10, 15, 21
  ];

  const k = Array.from({ length: 64 }, (_, i) => Math.floor(Math.abs(Math.sin(i + 1)) * 4294967296));

  const rotateLeft = (l: number, r: number) => (l << r) | (l >>> (32 - r));

  const msg = new TextEncoder().encode(text);
  const words = new Int32Array(((msg.length + 8) >> 6 << 4) + 16);
  for (let i = 0; i < msg.length; i++) words[i >> 2] |= msg[i] << (i % 4 << 3);
  words[msg.length >> 2] |= 0x80 << (msg.length % 4 << 3);
  words[words.length - 2] = msg.length << 3;

  let h0 = 1732584193;
  let h1 = -271733879;
  let h2 = -1732584194;
  let h3 = 271733878;

  for (let i = 0; i < words.length; i += 16) {
    let a = h0, b = h1, c = h2, d = h3;
    for (let j = 0; j < 64; j++) {
      let f, g;
      if (j < 16) {
        f = (b & c) | (~b & d);
        g = j;
      } else if (j < 32) {
        f = (d & b) | (~d & c);
        g = (5 * j + 1) % 16;
      } else if (j < 48) {
        f = b ^ c ^ d;
        g = (3 * j + 5) % 16;
      } else {
        f = c ^ (b | ~d);
        g = (7 * j) % 16;
      }
      const tmp = d;
      d = c;
      c = b;
      b = (b + rotateLeft((a + f + k[j] + words[i + g]), s[j])) | 0;
      a = tmp;
    }
    h0 = (h0 + a) | 0;
    h1 = (h1 + b) | 0;
    h2 = (h2 + c) | 0;
    h3 = (h3 + d) | 0;
  }

  const toHex = (n: number) => ('00000000' + (n >>> 0).toString(16)).slice(-8).match(/../g)!.reverse().join('');
  return toHex(h0) + toHex(h1) + toHex(h2) + toHex(h3);
}

// ERA 6: Industrial Crypto Standards (AES-GCM + PBKDF2)

/**
 * Derives a secure 256-bit key from a password and salt using PBKDF2.
 * Compliance: 04-compliance-security
 */
export async function deriveKey(password: string, salt: Uint8Array): Promise<CryptoKey> {
  const encoder = new TextEncoder();
  const baseKey = await crypto.subtle.importKey(
    'raw',
    encoder.encode(password),
    'PBKDF2',
    false,
    ['deriveKey']
  );

  return crypto.subtle.deriveKey(
    {
      name: 'PBKDF2',
      salt,
      iterations: 100000,
      hash: 'SHA-256'
    } as Pbkdf2Params,
    baseKey,
    { name: 'AES-GCM', length: 256 },
    true,
    ['encrypt', 'decrypt']
  );
}

/**
 * Encrypts a string using AES-GCM.
 * Returns a combined Uint8Array: [salt(16) | iv(12) | ciphertext]
 */
export async function encryptData(text: string, password: string): Promise<Uint8Array> {
  const encoder = new TextEncoder();
  const salt = crypto.getRandomValues(new Uint8Array(16));
  const iv = crypto.getRandomValues(new Uint8Array(12));

  const key = await deriveKey(password, salt);
  const encrypted = await crypto.subtle.encrypt(
    { name: 'AES-GCM', iv },
    key,
    encoder.encode(text)
  );

  const result = new Uint8Array(salt.length + iv.length + encrypted.byteLength);
  result.set(salt, 0);
  result.set(iv, salt.length);
  result.set(new Uint8Array(encrypted), salt.length + iv.length);

  return result;
}

/**
 * Decrypts a Uint8Array generated by encryptData.
 */
export async function decryptData(combined: Uint8Array, password: string): Promise<string> {
  const salt = combined.slice(0, 16);
  const iv = combined.slice(16, 28);
  const ciphertext = combined.slice(28);

  const key = await deriveKey(password, salt);
  const decrypted = await crypto.subtle.decrypt(
    { name: 'AES-GCM', iv },
    key,
    ciphertext
  );

  return new TextDecoder().decode(decrypted);
}

/**
 * High-security PIN Hashing for Industrial Authentication.
 * Uses SHA-256 with 100,000 iterations.
 */
export async function hashPin(pin: string): Promise<string> {
  const encoder = new TextEncoder();
  const data = encoder.encode(pin);
  // Using a fixed salt for deterministic local verification of PINs
  const salt = encoder.encode('ABDFN_INDUSTRIAL_SALT_v6'); 

  const baseKey = await crypto.subtle.importKey(
    'raw',
    data,
    'PBKDF2',
    false,
    ['deriveBits']
  );

  const derivedBits = await crypto.subtle.deriveBits(
    {
      name: 'PBKDF2',
      salt: salt,
      iterations: 100000,
      hash: 'SHA-256'
    },
    baseKey,
    256
  );

  return Array.from(new Uint8Array(derivedBits))
    .map(b => b.toString(16).padStart(2, '0'))
    .join('');
}

/**
 * EncryptionMigration - Maintenance utility for at-rest encryption (Phase 14).
 * Migrates existing plain-text records to encrypted containers.
 */

import { coreDb } from '../db/SystemDB';
import { ABDFNSuiteDB } from '../db/db';
import { CryptoService } from '../services/crypto.service';

export class EncryptionMigration {

  /**
   * Migrates core records (Operators mfaSecret).
   */
  public static async migrateCore(installationKey: CryptoKey): Promise<{ success: number; skipped: number }> {
    let success = 0;
    let skipped = 0;

    await coreDb.operators.toCollection().each(async (op: any) => {
      // 1. Skip if already encrypted or empty
      if (!op.mfaSecret || (typeof op.mfaSecret === 'object' && (op.mfaSecret as any).v === 1)) {
        skipped++;
        return;
      }

      // 2. Encrypt
      try {
        const aad = CryptoService.buildAAD('ABDFN_CORE', null, 'operators', op.id, 'mfaSecret');
        op.mfaSecret = await CryptoService.encryptField(op.mfaSecret, installationKey, aad);
        await coreDb.operators.put(op);
        success++;
      } catch (err) {
        console.error(`[MIGRATION-CORE] Failed to encrypt mfaSecret for ${op.username}`, err);
      }
    });

    return { success, skipped };
  }

  /**
   * Migrates unit-specific records (Templates, Audits).
   */
  public static async migrateUnit(
      db: ABDFNSuiteDB, 
      unitId: string, 
      installationKey: CryptoKey
  ): Promise<{ success: number; skipped: number }> {
    let success = 0;
    let skipped = 0;

    // Migrate Templates
    await db.lettertemplates_v6.toCollection().each(async (tmpl: any) => {
        let modified = false;

        // Content (HTML)
        if (tmpl.content && (typeof tmpl.content !== 'object' || (tmpl.content as any).v !== 1)) {
            const aad = CryptoService.buildAAD('ABDFN_SUITE', unitId, 'lettertemplates_v6', tmpl.id, 'content');
            tmpl.content = await CryptoService.encryptField(tmpl.content, installationKey, aad);
            modified = true;
        }

        // BinaryContent (DOCX)
        if (tmpl.binaryContent && (typeof tmpl.binaryContent !== 'object' || (tmpl.binaryContent as any).v !== 1)) {
            const aad = CryptoService.buildAAD('ABDFN_SUITE', unitId, 'lettertemplates_v6', tmpl.id, 'binaryContent');
            tmpl.binaryContent = await CryptoService.encryptField(tmpl.binaryContent, installationKey, aad);
            modified = true;
        }

        if (modified) {
            await db.lettertemplates_v6.put(tmpl);
            success++; 
        } else {
            skipped++;
        }
    });

    // Migrate Audit History
    await db.audit_history_v6.toCollection().each(async (rec: any) => {
        if (rec.details && (typeof rec.details !== 'object' || (rec.details as any).v !== 1)) {
            const aad = CryptoService.buildAAD('ABDFN_SUITE', unitId, 'audit_history_v6', rec.id, 'details');
            rec.details = await CryptoService.encryptField(rec.details, installationKey, aad);
            await db.audit_history_v6.put(rec);
            success++;
        } else {
            skipped++;
        }
    });

    return { success, skipped };
  }
}

import { EtlPreset, EtlRecordType, EtlField, EtlRecordBehavior } from '../types/etl.types';

/**
 * Robust Normalizer for ETL Presets.
 * Handles Legacy (flat), Modern C# (object-based Spanish), and Suite (array-based English) formats.
 */
export function normalizeEtlPreset(data: any): EtlPreset {
  const result: EtlPreset = {
    name: data.name || data.nombre_mostrar || data.nombre || 'IMPORTED_PRESET',
    version: data.version || '1.0',
    description: data.description || '',
    chunkSize: data.chunkSize || data.max_filas_por_csv || 900000,
    encoding: (data.encoding || data.codificacion || 'utf-8').toLowerCase() === 'latin1' ? 'windows-1252' : (data.encoding || data.codificacion || 'utf-8'),

    recordTypeStart: data.recordTypeStart ?? data.inicio_tipo_registro ?? 0,
    recordTypeLen: data.recordTypeLen ?? data.longitud_tipo_registro ?? 0,
    defaultRecordType: data.defaultRecordType ?? data.tipo_registro_por_defecto ?? '',
    headerTypeId: data.headerTypeId ?? data.id_tipo_cabecera ?? '',

    recordTypes: [],
    isActive: true,
    createdAt: data.createdAt || Date.now(),
    updatedAt: Date.now()
  };

  // Case 1: Suite Format (Current)
  if (Array.isArray(data.recordTypes)) {
    result.recordTypes = data.recordTypes;
    return result;
  }

  // Case 2: Modern C# Format (Spanish object-based record types)
  if (data.tipos_registro && typeof data.tipos_registro === 'object') {
    const triggerStart = data.inicio_tipo_registro || 0;
    const headerId = data.id_tipo_cabecera || '';

    result.recordTypes = Object.entries(data.tipos_registro).map(([trigger, fields]: [string, any]) => {
      const isHeader = trigger === headerId;
      return {
        name: isHeader ? 'HEADER' : `DATA_${trigger}`,
        trigger: trigger === 'default' ? '' : trigger,
        triggerStart: triggerStart,
        behavior: (isHeader ? 'HEADER' : 'DATA') as EtlRecordBehavior,
        range: isHeader ? '1' : '',
        fields: fields.map((f: any) => ({
          name: f.nombre || f.name,
          start: f.inicio ?? f.start ?? 0,
          length: f.longitud || f.length || 0
        }))
      };
    });
    return result;
  }

  // Case 3: Legacy Format (Spanish flat field list, sequential)
  if (Array.isArray(data.campos)) {
    let currentPos = 0;
    const fields: EtlField[] = data.campos.map((f: any) => {
      const field = {
        name: f.nombre || f.name,
        start: f.inicio ?? f.start ?? currentPos, // Use start if exists, else sequence
        length: f.longitud || f.length || 0
      };
      // If start wasn't provided, move the cursor
      if (f.inicio === undefined && f.start === undefined) {
        currentPos += field.length;
      }
      return field;
    });

    result.recordTypes = [{
      name: 'UNIVERSAL',
      trigger: '',
      triggerStart: 0,
      behavior: 'DATA',
      range: '',
      fields: fields
    }];
    return result;
  }

  return result;
}

/**
 * Filename Sanitization Utility
 * Compliance: 04-compliance-security (Advanced Defense)
 */

/**
 * Sanitizes a filename to prevent path traversal and remove forbidden characters.
 * @param filename The original filename
 * @param replacement Character to replace invalid ones with (default: '_')
 * @returns Sanitized filename
 */
export function sanitizeFilename(filename: string, replacement: string = '_'): string {
  if (!filename) return 'ABDFN_GEN_UNNAMED';

  // 1. Remove control characters and reserved characters across OSs
  // Forbidden in Windows: < > : " / \ | ? *
  // Forbidden in Unix: / (and NULL)
  let sanitized = filename.replace(/[<>:"/\\|?*\x00-\x1F]/g, replacement);

  // 2. Prevent path traversal (..)
  sanitized = sanitized.replace(/\.\.+/g, replacement);

  // 3. Prevent hidden files (Unix starts with .)
  if (sanitized.startsWith('.')) {
    sanitized = 'DATA' + sanitized;
  }

  // 4. Trace-back and Trim
  sanitized = sanitized.trim();

  if (sanitized === '.' || sanitized === '..') {
    return 'ABDFN_GEN_UNNAMED';
  }

  // 5. Length Limit (Industrial legacy often limits to 255 or even 40)
  const MAX_LENGTH = 120;
  if (sanitized.length > MAX_LENGTH) {
    sanitized = sanitized.substring(0, MAX_LENGTH);
  }

  return sanitized || 'ABDFN_GEN_UNNAMED';
}

